/**
 * Local audit for phone + OTP web login (`POST /api/v2/auth/web/session/otp`).
 * Run from apps/api: pnpm auth:debug-audit
 */
import * as argon2 from "argon2";
import { randomUUID } from "node:crypto";
import { DataSource, IsNull } from "typeorm";
import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { UserRole } from "../common/auth/user-role.enum";
import { TenantEntity } from "../modules/identity/entities/tenant.entity";
import { UserEntity } from "../modules/identity/entities/user.entity";
import { UserTenantEntity } from "../modules/identity/entities/user-tenant.entity";

const EMAIL = "leader@test.com";
const PHONE = "+15551234567";
const STATIC_OTP = "1234";
const TENANT_NAME = "demo-tenant";

function assertDbEnv(): void {
  const keys = ["DATABASE_HOST", "DATABASE_USER", "DATABASE_PASSWORD", "DATABASE_NAME"] as const;
  for (const k of keys) {
    const v = process.env[k];
    if (v === undefined || v === "") {
      throw new Error(`Missing env ${k}. Use apps/api/.env (see .env.example).`);
    }
    if (k === "DATABASE_PASSWORD" && typeof v !== "string") {
      throw new Error("DATABASE_PASSWORD must be a string");
    }
  }
}

async function simulateOtpSessionChecks(params: {
  dataSource: DataSource;
  phone: string;
  otp: string;
  tenantId: string;
}): Promise<{ ok: true } | { ok: false; reason: string }> {
  if (process.env.NODE_ENV === "production") {
    return { ok: false, reason: "static OTP checks disabled in production NODE_ENV" };
  }
  if (params.otp !== STATIC_OTP) {
    return { ok: false, reason: "AUTH_UNAUTHENTICATED (OTP mismatch for non-production static policy)" };
  }
  const user = await params.dataSource
    .getRepository(UserEntity)
    .createQueryBuilder("u")
    .where("u.deleted_at IS NULL")
    .andWhere("phone_normalized(u.phone) = phone_normalized(:phone)", { phone: params.phone.trim() })
    .getOne();
  if (!user) {
    return { ok: false, reason: "AUTH_UNAUTHENTICATED (no user for normalized phone)" };
  }
  const membership = await params.dataSource.getRepository(UserTenantEntity).findOne({
    where: { userId: user.id, tenantId: params.tenantId, deletedAt: IsNull() }
  });
  if (!membership) {
    return { ok: false, reason: "TENANT_SCOPE_FORBIDDEN (no membership for tenant)" };
  }
  return { ok: true };
}

async function httpLoginSession(baseUrl: string, hostHeader: string): Promise<{
  ok: boolean;
  status?: number;
  session_token?: string;
  error?: string;
}> {
  const url = `${baseUrl.replace(/\/$/, "")}/api/v2/auth/web/session/otp`;
  const body = { phone: PHONE, otp: STATIC_OTP };
  try {
    const res = await fetch(url, {
      method: "POST",
      headers: { "Content-Type": "application/json", Host: hostHeader },
      body: JSON.stringify(body)
    });
    const text = await res.text();
    let json: { session_token?: string } = {};
    try {
      json = JSON.parse(text) as { session_token?: string };
    } catch {
      /* ignore */
    }
    if (!res.ok) {
      return { ok: false, status: res.status, error: text.slice(0, 500) };
    }
    return { ok: true, status: res.status, session_token: json.session_token };
  } catch (e) {
    const msg = e instanceof Error ? e.message : String(e);
    return { ok: false, error: msg };
  }
}

async function run(): Promise<void> {
  assertDbEnv();

  const dataSource = new DataSource({
    ...createDataSourceOptionsFromEnv(),
    entities: [TenantEntity, UserEntity, UserTenantEntity]
  });

  await dataSource.initialize();

  let loginStatus: "success" | "failure" = "failure";

  try {
    const tenantRepo = dataSource.getRepository(TenantEntity);
    const userRepo = dataSource.getRepository(UserEntity);
    const membershipRepo = dataSource.getRepository(UserTenantEntity);

    let tenant = await tenantRepo.findOne({
      where: { name: TENANT_NAME, deletedAt: IsNull() }
    });
    if (!tenant) {
      tenant = await tenantRepo.save(
        tenantRepo.create({
          name: TENANT_NAME,
          description: "Created by auth-debug-audit",
          subdomain: "demo"
        })
      );
    } else if (!tenant.subdomain?.trim()) {
      tenant.subdomain = "demo";
      await tenantRepo.save(tenant);
    }

    let user = await userRepo.findOne({
      where: { email: EMAIL, deletedAt: IsNull() }
    });

    if (!user) {
      user = await userRepo.save(
        userRepo.create({
          email: EMAIL,
          phone: PHONE,
          isPhoneVerified: true,
          hashedPassword: await argon2.hash(`fixture-${randomUUID()}`),
          fullName: "Audit Leader",
          isEmailVerified: true,
          telegramUserId: null
        })
      );
    } else if (!user.phone?.trim()) {
      user.phone = PHONE;
      user.isPhoneVerified = true;
      await userRepo.save(user);
    }

    const membershipRow = await membershipRepo.findOne({
      where: { userId: user.id, tenantId: tenant!.id, deletedAt: IsNull() }
    });
    if (!membershipRow) {
      await membershipRepo.save(
        membershipRepo.create({
          tenantId: tenant!.id,
          userId: user.id,
          role: UserRole.Owner
        })
      );
    }


    const internal = await simulateOtpSessionChecks({
      dataSource,
      phone: PHONE,
      otp: STATIC_OTP,
      tenantId: tenant!.id
    });
    if (!internal.ok) {
      loginStatus = "failure";
    }

    const port = process.env.PORT ?? "3000";
    const baseUrl = process.env.AUTH_AUDIT_API_BASE ?? `http://127.0.0.1:${port}`;
    const tenantRoot = process.env.TENANT_ROOT_DOMAIN?.trim() || "localhost";
    const slug = tenant!.subdomain?.trim() || "demo";
    const hostHeader =
      tenantRoot === "localhost" ? `${slug}.localhost` : `${slug}.${tenantRoot}`;
    const http = await httpLoginSession(baseUrl, hostHeader);
    if (http.ok && http.session_token) {
      loginStatus = "success";
    } else {
      loginStatus = "failure";
      void http.error;
    }
  } finally {
    await dataSource.destroy();
  }

}

run().catch((error: unknown) => {
  process.exitCode = 1;
});

/**
 * Removes stale / debug rows from `draft_snapshots`.
 *
 * Targets:
 *   - draft_key = 'undefined'
 *   - draft_key LIKE 'debug-occ-%'
 *
 * Usage (from apps/api, uses .env):
 *   pnpm run cleanup:drafts
 *   pnpm run cleanup:drafts -- --dry-run
 */
import "reflect-metadata";

import { NestFactory } from "@nestjs/core";
import { DataSource } from "typeorm";

import { AppModule } from "../app.module";
import { DraftSnapshotEntity } from "../modules/draft-engine/entities/draft-snapshot.entity";
import { emitScriptInfo } from "./script-log";

const UNDEFINED_DRAFT_KEY = "undefined";
const DEBUG_OCC_PREFIX = "debug-occ-%";

const dryRun = process.argv.includes("--dry-run");

function describeDatabaseTarget(): string {
  const host = process.env.DATABASE_HOST ?? "(unset)";
  const port = process.env.DATABASE_PORT ?? "5432";
  const name = process.env.DATABASE_NAME ?? "(unset)";
  const user = process.env.DATABASE_USER ?? "(unset)";
  return `${user}@${host}:${port}/${name}`;
}

function staleDraftWhereClause(): string {
  return "(draft_key = :undefinedKey OR draft_key LIKE :debugPrefix)";
}

function staleDraftParams(): { undefinedKey: string; debugPrefix: string } {
  return { undefinedKey: UNDEFINED_DRAFT_KEY, debugPrefix: DEBUG_OCC_PREFIX };
}

async function countStaleDrafts(dataSource: DataSource): Promise<number> {
  return dataSource
    .getRepository(DraftSnapshotEntity)
    .createQueryBuilder("draft")
    .where(staleDraftWhereClause(), staleDraftParams())
    .getCount();
}

async function listStaleDraftSamples(
  dataSource: DataSource,
  limit = 25,
): Promise<Array<{ draftKey: string; workspaceId: string; userId: string; version: number }>> {
  const rows = await dataSource
    .getRepository(DraftSnapshotEntity)
    .createQueryBuilder("draft")
    .select(["draft.draftKey", "draft.workspaceId", "draft.userId", "draft.version"])
    .where(staleDraftWhereClause(), staleDraftParams())
    .orderBy("draft.updatedAt", "DESC")
    .limit(limit)
    .getMany();

  return rows.map((row) => ({
    draftKey: row.draftKey,
    workspaceId: row.workspaceId,
    userId: row.userId,
    version: row.version,
  }));
}

async function deleteStaleDrafts(dataSource: DataSource): Promise<number> {
  const result = await dataSource
    .getRepository(DraftSnapshotEntity)
    .createQueryBuilder()
    .delete()
    .where(staleDraftWhereClause(), staleDraftParams())
    .execute();

  return result.affected ?? 0;
}

async function main(): Promise<void> {
  if (!process.env.DATABASE_HOST || !process.env.DATABASE_NAME) {
    throw new Error(
      "cleanup-drafts: DATABASE_HOST and DATABASE_NAME must be set (run via pnpm run cleanup:drafts from apps/api with --env-file=.env).",
    );
  }

  emitScriptInfo("cleanup-drafts: bootstrapping Nest application context…");
  emitScriptInfo(`cleanup-drafts: database target → ${describeDatabaseTarget()}`);
  emitScriptInfo(`cleanup-drafts: mode → ${dryRun ? "DRY RUN (no deletes)" : "LIVE DELETE"}`);

  const app = await NestFactory.createApplicationContext(AppModule, {
    logger: ["error", "warn"],
  });

  try {
    const dataSource = app.get(DataSource);

    const countBefore = await countStaleDrafts(dataSource);
    emitScriptInfo(
      `cleanup-drafts: rows matching criteria (undefined key or debug-occ-*): ${countBefore}`,
    );

    if (countBefore > 0) {
      const samples = await listStaleDraftSamples(dataSource);
      emitScriptInfo(`cleanup-drafts: sample rows (up to ${samples.length}):`);
      for (const sample of samples) {
        emitScriptInfo(
          `  draft_key=${sample.draftKey} workspace_id=${sample.workspaceId} user_id=${sample.userId} version=${sample.version}`,
        );
      }
    }

    if (dryRun) {
      emitScriptInfo(
        `cleanup-drafts: dry run complete — would delete ${countBefore} row(s). Re-run without --dry-run to apply.`,
      );
      return;
    }

    if (countBefore === 0) {
      emitScriptInfo("cleanup-drafts: nothing to delete.");
      return;
    }

    const affected = await deleteStaleDrafts(dataSource);
    const countAfter = await countStaleDrafts(dataSource);

    emitScriptInfo(`cleanup-drafts: delete executed — affected rows: ${affected}`);
    emitScriptInfo(`cleanup-drafts: remaining matching rows: ${countAfter}`);

    if (countAfter > 0) {
      throw new Error(
        `cleanup-drafts: expected 0 stale rows after delete, found ${countAfter}.`,
      );
    }

    emitScriptInfo("cleanup-drafts: completed successfully.");
  } finally {
    try {
      await app.close();
    } catch (closeError: unknown) {
      const message =
        closeError instanceof Error ? closeError.message : String(closeError);
      emitScriptInfo(`cleanup-drafts: warning — app.close(): ${message}`);
    }
  }
}

void main().catch((error: unknown) => {
  process.exit(1);
});

/**
 * Wipes legacy workspace tour templates/presets and verifies canonical-only storage.
 *
 * Usage: ALLOW_LEGACY_TEMPLATE_WIPE=1 pnpm --filter api cleanup:legacy-templates
 */
import { DataSource } from "typeorm";

import { TEMPLATE_SCHEMA_ALIGNED_WITH_CANONICAL_MODEL } from "@repo/types/denali";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import {
  cleanupLegacyTemplates,
  verifyCanonicalTemplateStorageIsClean,
} from "../modules/settings-locations/cleanup-legacy-templates.util";
import { emitScriptInfo } from "./script-log";

async function main(): Promise<void> {
  if (process.env.ALLOW_LEGACY_TEMPLATE_WIPE !== "1") {
    process.exitCode = 1;
    return;
  }

  if (!TEMPLATE_SCHEMA_ALIGNED_WITH_CANONICAL_MODEL) {
    throw new Error("Denali template schema is not aligned with DenaliCanonicalTourModel");
  }

  const dataSource = new DataSource(createDataSourceOptionsFromEnv());
  await dataSource.initialize();
  try {
    const report = await cleanupLegacyTemplates(dataSource);
    emitScriptInfo(`cleanup report: ${JSON.stringify(report)}`);

    const verification = await verifyCanonicalTemplateStorageIsClean(dataSource);
    emitScriptInfo(`post-cleanup: ${JSON.stringify(verification)}`);

    if (report.presetsDeleted > 0 && verification.presetCount !== 0) {
      throw new Error(
        `Expected preset table empty after cleanup, found ${verification.presetCount}`,
      );
    }

    const legacyCanonical = await dataSource.query<
      Array<{ id: string; canonical_data: unknown; defaults: unknown }>
    >(`SELECT id, canonical_data, defaults FROM workspace_tour_creation_presets LIMIT 5`);
    if (legacyCanonical.length > 0) {
      throw new Error("Preset rows remain after cleanup");
    }

    emitScriptInfo("Template storage is canonical-schema driven (DenaliCanonicalTourModel).");
  } finally {
    await dataSource.destroy();
  }
}

void main().catch((err) => {
  process.exit(1);
});

/**
 * Hard-deletes all tours (and booking/payment rows tied to those tours) for the Denali workspace.
 * Preserves tenant, owner, equipment/themes/destinations presets, and wizard templates.
 *
 * ```bash
 * ALLOW_DENALI_TOUR_DELETE=1 pnpm --filter @apps/api delete:denali-tours
 * ```
 */
import { DataSource } from "typeorm";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { DENALI_SUBDOMAIN } from "./denali-tenant.fixture";
import { emitScriptInfo } from "./script-log";

type CountRow = { c: string };

function fail(message: string): never {
  throw new Error(message);
}

async function deleteCount(
  ds: DataSource,
  label: string,
  sql: string,
  params: unknown[],
): Promise<number> {
  const counted = await ds.query<CountRow[]>(
    `WITH d AS (${sql} RETURNING 1) SELECT count(*)::text AS c FROM d`,
    params,
  );
  const n = Number(counted[0]?.c ?? 0);
  emitScriptInfo(`  ${label}: ${n}`);
  return n;
}

export type DeleteDenaliToursSummary = {
  tenantId: string;
  subdomain: string;
  toursBefore: number;
  deleted: Record<string, number>;
};

export async function deleteDenaliTours(): Promise<DeleteDenaliToursSummary> {
  if (process.env.ALLOW_DENALI_TOUR_DELETE?.trim() !== "1") {
    fail(
      "delete-denali-tours: set ALLOW_DENALI_TOUR_DELETE=1 to run. This permanently removes all tours for the Denali workspace.",
    );
  }
  if (process.env.NODE_ENV === "production" && process.env.ALLOW_DENALI_TOUR_DELETE !== "true") {
    fail(
      "delete-denali-tours: refusing production. Set ALLOW_DENALI_TOUR_DELETE=true after explicit review.",
    );
  }

  const ds = new DataSource({
    ...createDataSourceOptionsFromEnv(),
    entities: [],
  });

  await ds.initialize();
  const deleted: Record<string, number> = {};

  try {
    const tenantRows = await ds.query<Array<{ id: string; subdomain: string }>>(
      `SELECT id, subdomain FROM tenants WHERE subdomain = $1 AND deleted_at IS NULL LIMIT 1`,
      [DENALI_SUBDOMAIN],
    );
    const tenant = tenantRows[0];
    if (!tenant) {
      fail(`delete-denali-tours: tenant subdomain "${DENALI_SUBDOMAIN}" not found.`);
    }

    const beforeRows = await ds.query<CountRow[]>(
      `SELECT count(*)::text AS c FROM tours WHERE tenant_id = $1`,
      [tenant.id],
    );
    const toursBefore = Number(beforeRows[0]?.c ?? 0);

    emitScriptInfo(
      `=== Deleting Denali tours (tenant=${tenant.subdomain}, tours_before=${toursBefore}) ===`,
    );

    await ds.query("BEGIN");
    try {
      deleted.payment_receipts = await deleteCount(
        ds,
        "payment_receipts",
        `DELETE FROM payment_receipts WHERE tenant_id = $1`,
        [tenant.id],
      );

      deleted.payments = await deleteCount(
        ds,
        "payments",
        `DELETE FROM payments WHERE tenant_id = $1`,
        [tenant.id],
      );

      deleted.booking_price_snapshots = await deleteCount(
        ds,
        "booking_price_snapshots",
        `DELETE FROM booking_price_snapshots WHERE tenant_id = $1`,
        [tenant.id],
      );

      deleted.waitlist_items = await deleteCount(
        ds,
        "waitlist_items",
        `DELETE FROM waitlist_items WHERE tenant_id = $1`,
        [tenant.id],
      );

      deleted.registrations = await deleteCount(
        ds,
        "registrations",
        `DELETE FROM registrations WHERE tenant_id = $1`,
        [tenant.id],
      );

      deleted.tour_details = await deleteCount(
        ds,
        "tour_details",
        `DELETE FROM tour_details WHERE tour_id IN (SELECT id FROM tours WHERE tenant_id = $1)`,
        [tenant.id],
      );

      deleted.tours = await deleteCount(
        ds,
        "tours",
        `DELETE FROM tours WHERE tenant_id = $1`,
        [tenant.id],
      );

      deleted.tour_departures = await deleteCount(
        ds,
        "tour_departures",
        `DELETE FROM tour_departures WHERE tenant_id = $1`,
        [tenant.id],
      );

      deleted.tour_products = await deleteCount(
        ds,
        "tour_products",
        `DELETE FROM tour_products WHERE tenant_id = $1`,
        [tenant.id],
      );

      await ds.query("COMMIT");
    } catch (error) {
      await ds.query("ROLLBACK");
      throw error;
    }

    const summary: DeleteDenaliToursSummary = {
      tenantId: tenant.id,
      subdomain: tenant.subdomain,
      toursBefore,
      deleted,
    };

    emitScriptInfo("=== Denali tours deleted ===");
    emitScriptInfo(JSON.stringify(summary, null, 2));
    return summary;
  } finally {
    if (ds.isInitialized) {
      await ds.destroy();
    }
  }
}

const isDirectRun =
  typeof process.argv[1] === "string" && process.argv[1].includes("delete-denali-tours");

if (isDirectRun) {
  deleteDenaliTours().catch((error: unknown) => {
    process.exitCode = 1;
  });
}

/**
 * Denali Wizard QA — Phase 3: SQL Integrity Audit.
 */
import { DataSource } from "typeorm";
import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { DENALI_SUBDOMAIN } from "./denali-tenant.fixture";
import { emitScriptInfo } from "./script-log";

async function denaliSqlAudit(): Promise<void> {
  emitScriptInfo("=== Denali Wizard QA Phase 3: SQL Integrity Audit ===");

  const ds = new DataSource(createDataSourceOptionsFromEnv());
  await ds.initialize();

  try {
    const tenants = await ds.query<Array<{ id: string }>>(
      `SELECT id FROM tenants WHERE deleted_at IS NULL AND lower(trim(subdomain)) = lower(trim($1)) LIMIT 1`,
      [DENALI_SUBDOMAIN],
    );
    const tenant = tenants[0];
    if (!tenant) {
      throw new Error(`Tenant subdomain "${DENALI_SUBDOMAIN}" not found.`);
    }
    const workspaceId = tenant.id;
    const tenantId = tenant.id;

    const queries = [
      {
        id: "3.1",
        name: "ناهماهنگی preset: ستون match vs JSONB",
        sql: `SELECT id, name, match_main_tour_theme_id,
                     defaults->'programNature'->>'mainTourThemeId' AS json_main
              FROM workspace_tour_creation_presets
              WHERE workspace_id = $1
                AND match_main_tour_theme_id IS DISTINCT FROM
                    (defaults->'programNature'->>'mainTourThemeId')::uuid`,
        params: [workspaceId],
      },
      {
        id: "3.2",
        name: "orphan theme UUID در presets",
        sql: `SELECT p.id, p.match_main_tour_theme_id
              FROM workspace_tour_creation_presets p
              WHERE p.workspace_id = $1
                AND p.match_main_tour_theme_id IS NOT NULL
                AND NOT EXISTS (
                  SELECT 1 FROM workspace_tour_themes t
                  WHERE t.id = p.match_main_tour_theme_id AND t.workspace_id = p.workspace_id
                )`,
        params: [workspaceId],
      },
      {
        id: "3.3",
        name: "orphan theme UUID در tours",
        sql: `SELECT t.id AS tour_id, e.theme_id
              FROM tours t
              JOIN tour_details td ON td.tour_id = t.id
              CROSS JOIN LATERAL jsonb_array_elements_text(
                COALESCE(td.trip_details->'overview'->'tourThemeIds', '[]'::jsonb)
              ) e(theme_id)
              WHERE t.tenant_id = $1
                AND NOT EXISTS (
                  SELECT 1 FROM workspace_tour_themes w
                  WHERE w.id::text = e.theme_id AND w.workspace_id = t.tenant_id
                )`,
        params: [tenantId],
      },
      {
        id: "3.4",
        name: "ghost: event + overview.difficultyLevel",
        sql: `SELECT t.id, td.trip_details->'overview'->>'denaliTourKind'
              FROM tours t
              JOIN tour_details td ON td.tour_id = t.id
              WHERE t.tenant_id = $1
                AND (td.trip_details->'overview'->>'denaliTourKind') LIKE 'event_%'
                AND (td.trip_details->'overview'->>'difficultyLevel') IS NOT NULL`,
        params: [tenantId],
      },
      {
        id: "3.5",
        name: "ghost: event preset + outdoor در programNature",
        sql: `SELECT id, name
              FROM workspace_tour_creation_presets
              WHERE workspace_id = $1
                AND (defaults->'basicInfo'->>'tourType') LIKE 'event_%'
                AND (
                  defaults->'programNature'->>'difficultyLevel' IS NOT NULL
                  OR defaults->'programNature'->>'hikingHoursApprox' IS NOT NULL
                )`,
        params: [workspaceId],
      },
      {
        id: "3.6",
        name: "توزیع تم‌ها روی tours",
        sql: `SELECT wt.slug, count(*)
              FROM tours t
              JOIN tour_details td ON td.tour_id = t.id
              CROSS JOIN LATERAL jsonb_array_elements_text(
                COALESCE(td.trip_details->'overview'->'tourThemeIds', '[]'::jsonb)
              ) e(theme_id)
              JOIN workspace_tour_themes wt ON wt.id::text = e.theme_id
              WHERE t.tenant_id = $1
              GROUP BY wt.slug`,
        params: [tenantId],
      },
      {
        id: "3.7",
        name: "single-day با returnDate باقی‌مانده (ghost logistics)",
        sql: `SELECT t.id, td.trip_details->'overview'->>'denaliTourKind',
                     td.trip_details->'logistics'->>'returnDate'
              FROM tours t
              JOIN tour_details td ON td.tour_id = t.id
              WHERE t.tenant_id = $1
                AND (td.trip_details->'overview'->>'denaliTourKind') LIKE '%_day'
                AND (td.trip_details->'logistics'->>'returnDate') IS NOT NULL`,
        params: [tenantId],
      },
    ];

    let overallSuccess = true;
    for (const q of queries) {
      const rows = await ds.query(q.sql, q.params);
      const rowCount = Array.isArray(rows) ? rows.length : 0;

      if (q.id === "3.6") {
        emitScriptInfo(`📊 ${q.id} ${q.name}:`);
        console.table(rows);
      } else {
        if (rowCount === 0) {
          emitScriptInfo(`✅ ${q.id} ${q.name}: 0 rows (PASS)`);
        } else {
          emitScriptInfo(`❌ ${q.id} ${q.name}: ${rowCount} rows (FAIL)`);
          console.table(rows.slice(0, 5));
          overallSuccess = false;
        }
      }
    }

    if (!overallSuccess) {
      process.exitCode = 2;
    }
  } finally {
    await ds.destroy();
  }
}

denaliSqlAudit().catch((err) => {
  process.exit(1);
});

/**
 * Denali Wizard QA — Phase 2: Apply theme consolidation + UUID remap.
 *
 * 1. Upsert consolidated themes (`nature`, `mountain`)
 * 2. Remap preset defaults + match_main_tour_theme_id
 * 3. Remap tour trip_details.overview.tourThemeIds
 * 4. Ghost-field sanitize (event presets / tours)
 * 5. Hard-delete legacy workspace themes
 *
 * ```bash
 * ALLOW_DENALI_THEME_APPLY=1 pnpm --filter @apps/api qa:denali:theme-apply
 * ALLOW_DENALI_THEME_APPLY=1 pnpm --filter @apps/api qa:denali:theme-apply --log=./denali-theme-apply.log
 * ALLOW_DENALI_THEME_APPLY=1 pnpm --filter @apps/api qa:denali:theme-apply -- --dry-run
 * ```
 */
import fs from "node:fs";
import path from "node:path";
import { randomUUID } from "node:crypto";
import { DataSource } from "typeorm";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { DENALI_SUBDOMAIN } from "./denali-tenant.fixture";
import {
  DENALI_CONSOLIDATED_THEME_SEEDS,
  resolveConsolidatedThemeSlug,
  sanitizePresetDefaultsGhost,
  sanitizeTripDetailsGhost,
  type ConsolidatedThemeSlug,
} from "./denali-theme-migration.shared";
import { emitScriptInfo } from "./script-log";

const REPO_ROOT = path.resolve(__dirname, "../../../..");
const MAP_LOG = path.join(REPO_ROOT, "map.log");

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

type ThemeRow = { id: string; slug: string; name: string };
type PresetRow = {
  id: string;
  name: string;
  match_tour_type: string | null;
  match_main_tour_theme_id: string | null;
  defaults: Record<string, unknown>;
};
type TourRow = { tour_id: string; trip_details: Record<string, unknown> | null };

function fail(message: string): never {
  throw new Error(message);
}

function resolveLogPathFromArgv(argv: readonly string[]): string {
  for (const arg of argv) {
    if (arg.startsWith("--log=")) {
      return path.resolve(REPO_ROOT, arg.slice("--log=".length));
    }
  }
  return MAP_LOG;
}

function parseDryRun(argv: readonly string[]): boolean {
  return argv.includes("--dry-run");
}

function assertApplyAllowed(): void {
  if (process.env.NODE_ENV === "production" && process.env.ALLOW_DENALI_THEME_APPLY !== "true") {
    fail(
      "denali-theme-apply: refusing production. Set ALLOW_DENALI_THEME_APPLY=true after explicit review.",
    );
  }
  if (process.env.ALLOW_DENALI_THEME_APPLY !== "1" && process.env.ALLOW_DENALI_THEME_APPLY !== "true") {
    fail("denali-theme-apply: set ALLOW_DENALI_THEME_APPLY=1 to execute.");
  }
}

function remapThemeId(
  oldId: string,
  oldSlugById: Map<string, string>,
  presetMatchTourType: string | null | undefined,
  newIdsBySlug: Map<ConsolidatedThemeSlug, string>,
): string | null {
  const oldSlug = oldSlugById.get(oldId);
  if (!oldSlug) {
    return null;
  }
  const target = resolveConsolidatedThemeSlug(oldSlug, presetMatchTourType);
  return newIdsBySlug.get(target) ?? null;
}

function remapThemeIdArray(
  ids: unknown,
  oldSlugById: Map<string, string>,
  matchTourType: string | null | undefined,
  newIdsBySlug: Map<ConsolidatedThemeSlug, string>,
): { ids: string[]; unmapped: string[] } {
  if (!Array.isArray(ids)) {
    return { ids: [], unmapped: [] };
  }
  const out: string[] = [];
  const unmapped: string[] = [];
  const seen = new Set<string>();
  const validNew = new Set(newIdsBySlug.values());
  for (const raw of ids) {
    if (typeof raw !== "string" || !UUID_RE.test(raw)) {
      continue;
    }
    const mapped = remapThemeId(raw, oldSlugById, matchTourType, newIdsBySlug);
    if (!mapped || !validNew.has(mapped)) {
      unmapped.push(raw);
      continue;
    }
    if (!seen.has(mapped)) {
      seen.add(mapped);
      out.push(mapped);
    }
  }
  return { ids: out, unmapped };
}

export type DenaliThemeApplyReport = {
  timestamp: string;
  dryRun: boolean;
  workspaceId: string;
  removedThemes: Array<{ id: string; slug: string; action: "REMOVE" }>;
  addedThemes: Array<{ id: string; slug: string; name: string; action: "ADD" }>;
  remappedPresets: Array<{ id: string; name: string; fromThemeId: string | null; toThemeId: string }>;
  remappedTours: Array<{ tourId: string; fromThemeIds: string[]; toThemeIds: string[] }>;
  ghostValidation: {
    presetsSanitized: number;
    toursSanitized: number;
    warnings: string[];
  };
  manualReview: {
    unmappedPresetThemeIds: string[];
    unmappedTourThemeIds: string[];
    orphanThemeRefsAfterApply: number;
  };
};

export async function denaliThemeApply(options?: {
  logPath?: string;
  dryRun?: boolean;
}): Promise<number> {
  const logPath = options?.logPath ?? MAP_LOG;
  const dryRun = options?.dryRun ?? false;

  emitScriptInfo(`=== Denali Theme Apply Phase 2${dryRun ? " (DRY RUN)" : ""} ===`);
  if (!dryRun) {
    assertApplyAllowed();
  }

  const ds = new DataSource(createDataSourceOptionsFromEnv());
  await ds.initialize();

  const ghostWarnings: string[] = [];
  const remappedPresets: DenaliThemeApplyReport["remappedPresets"] = [];
  const remappedTours: DenaliThemeApplyReport["remappedTours"] = [];
  const unmappedPresetThemeIds = new Set<string>();
  const unmappedTourThemeIds = new Set<string>();

  try {
    const tenants = await ds.query<Array<{ id: string }>>(
      `SELECT id FROM tenants WHERE deleted_at IS NULL AND lower(trim(subdomain)) = lower(trim($1)) LIMIT 1`,
      [DENALI_SUBDOMAIN],
    );
    const tenant = tenants[0];
    if (!tenant) {
      fail(`Tenant subdomain "${DENALI_SUBDOMAIN}" not found.`);
    }

    const legacyThemes = await ds.query<ThemeRow[]>(
      `SELECT id, slug, name FROM workspace_tour_themes WHERE workspace_id = $1 ORDER BY sort_order ASC`,
      [tenant.id],
    );
    const oldSlugById = new Map(legacyThemes.map((t) => [t.id, t.slug]));

    emitScriptInfo(`Legacy themes (${legacyThemes.length}): ${legacyThemes.map((t) => t.slug).join(", ")}`);

    const newIdsBySlug = new Map<ConsolidatedThemeSlug, string>();
    const addedThemes: DenaliThemeApplyReport["addedThemes"] = [];

    for (const spec of DENALI_CONSOLIDATED_THEME_SEEDS) {
      const existing = legacyThemes.find((t) => t.slug === spec.slug);
      const id = existing?.id ?? randomUUID();
      newIdsBySlug.set(spec.slug, id);
      addedThemes.push({ id, slug: spec.slug, name: spec.name, action: "ADD" });

      if (dryRun) {
        emitScriptInfo(`[dry-run] would upsert theme ${spec.slug} id=${id}`);
        continue;
      }

      await ds.query(
        `INSERT INTO workspace_tour_themes
          (id, workspace_id, slug, name, description, is_active, sort_order, form_profile)
         VALUES ($1, $2, $3, $4, $5, true, $6, $7)
         ON CONFLICT (workspace_id, slug) DO UPDATE SET
           name = EXCLUDED.name,
           description = EXCLUDED.description,
           is_active = true,
           sort_order = EXCLUDED.sort_order,
           form_profile = EXCLUDED.form_profile,
           updated_at = now()`,
        [id, tenant.id, spec.slug, spec.name, spec.description, spec.sortOrder, spec.formProfile],
      );
    }

    let presetsSanitized = 0;

    const presets = await ds.query<PresetRow[]>(
      `SELECT id, name, match_tour_type, match_main_tour_theme_id, defaults
       FROM workspace_tour_creation_presets
       WHERE workspace_id = $1`,
      [tenant.id],
    );

    for (const preset of presets) {
      const defaults = (preset.defaults ?? {}) as Record<string, unknown>;
      const programNature = (defaults.programNature ?? {}) as Record<string, unknown>;
      const oldMain =
        (typeof programNature.mainTourThemeId === "string" ? programNature.mainTourThemeId : null) ??
        preset.match_main_tour_theme_id;

      let newMain: string | null = null;
      if (oldMain && UUID_RE.test(oldMain)) {
        newMain = remapThemeId(oldMain, oldSlugById, preset.match_tour_type, newIdsBySlug);
        if (!newMain) {
          unmappedPresetThemeIds.add(oldMain);
        }
      }

      const secondaryRaw = programNature.secondaryTourThemeIds;
      const { ids: newSecondary, unmapped: secUnmapped } = remapThemeIdArray(
        secondaryRaw,
        oldSlugById,
        preset.match_tour_type,
        newIdsBySlug,
      );
      for (const u of secUnmapped) {
        unmappedPresetThemeIds.add(u);
      }

      if (!newMain && preset.match_tour_type) {
        const fallback = resolveConsolidatedThemeSlug("", preset.match_tour_type);
        newMain = newIdsBySlug.get(fallback) ?? null;
      }

      const nextDefaults = structuredClone(defaults) as Record<string, unknown>;
      if (newMain) {
        nextDefaults.programNature = {
          ...(nextDefaults.programNature as Record<string, unknown>),
          mainTourThemeId: newMain,
          ...(secondaryRaw != null ? { secondaryTourThemeIds: newSecondary } : {}),
        };
        remappedPresets.push({
          id: preset.id,
          name: preset.name,
          fromThemeId: oldMain,
          toThemeId: newMain,
        });
      }

      const ghost = sanitizePresetDefaultsGhost(nextDefaults);
      ghost.warnings.forEach((w) => ghostWarnings.push(`preset:${preset.name}: ${w}`));
      if (ghost.changed) {
        presetsSanitized += 1;
      }

      const finalDefaults = ghost.sanitized;
      const matchId = newMain ?? preset.match_main_tour_theme_id;
      const presetChanged = Boolean(newMain) || ghost.changed;

      if (dryRun) {
        if (newMain) {
          emitScriptInfo(`[dry-run] preset ${preset.name}: main ${oldMain} → ${newMain}`);
        }
        continue;
      }

      if (!presetChanged) {
        continue;
      }

      await ds.query(
        `UPDATE workspace_tour_creation_presets
         SET defaults = $1::jsonb,
             match_main_tour_theme_id = $2
         WHERE id = $3`,
        [JSON.stringify(finalDefaults), matchId, preset.id],
      );
    }

    const tours = await ds.query<TourRow[]>(
      `SELECT t.id AS tour_id, td.trip_details
       FROM tours t
       INNER JOIN tour_details td ON td.tour_id = t.id
       WHERE t.tenant_id = $1 AND td.trip_details IS NOT NULL`,
      [tenant.id],
    );

    let toursSanitized = 0;
    for (const row of tours) {
      const tripDetails = (row.trip_details ?? {}) as Record<string, unknown>;
      const overview = (tripDetails.overview ?? {}) as Record<string, unknown>;
      const denaliKind =
        typeof overview.denaliTourKind === "string" ? overview.denaliTourKind : null;
      const matchType =
        denaliKind?.startsWith("mountain") === true
          ? "mountain"
          : denaliKind?.startsWith("nature") === true || denaliKind?.startsWith("desert") === true
            ? "nature"
            : denaliKind?.startsWith("event") === true
              ? null
              : null;

      const { ids: newThemeIds, unmapped } = remapThemeIdArray(
        overview.tourThemeIds,
        oldSlugById,
        matchType,
        newIdsBySlug,
      );
      for (const u of unmapped) {
        unmappedTourThemeIds.add(u);
      }

      const nextTrip = structuredClone(tripDetails) as Record<string, unknown>;
      if (newThemeIds.length > 0) {
        nextTrip.overview = { ...((nextTrip.overview ?? {}) as Record<string, unknown>), tourThemeIds: newThemeIds };
        const fromIds = Array.isArray(overview.tourThemeIds)
          ? (overview.tourThemeIds as string[]).filter((x) => typeof x === "string")
          : [];
        if (fromIds.join(",") !== newThemeIds.join(",")) {
          remappedTours.push({ tourId: row.tour_id, fromThemeIds: fromIds, toThemeIds: newThemeIds });
        }
      }

      const ghost = sanitizeTripDetailsGhost(nextTrip);
      ghost.warnings.forEach((w) => ghostWarnings.push(`tour:${row.tour_id}: ${w}`));
      if (ghost.changed) {
        toursSanitized += 1;
      }

      if (dryRun) {
        continue;
      }

      await ds.query(`UPDATE tour_details SET trip_details = $1::jsonb WHERE tour_id = $2`, [
        JSON.stringify(ghost.sanitized),
        row.tour_id,
      ]);
    }

    const removedThemes = legacyThemes
      .filter((t) => !DENALI_CONSOLIDATED_THEME_SEEDS.some((s) => s.slug === t.slug))
      .map((t) => ({ id: t.id, slug: t.slug, action: "REMOVE" as const }));

    if (!dryRun && removedThemes.length > 0) {
      await ds.query(
        `DELETE FROM workspace_tour_themes
         WHERE workspace_id = $1 AND slug <> ALL($2::text[])`,
        [tenant.id, DENALI_CONSOLIDATED_THEME_SEEDS.map((s) => s.slug)],
      );
      emitScriptInfo(`Removed ${removedThemes.length} legacy theme row(s).`);
    } else if (dryRun) {
      emitScriptInfo(`[dry-run] would remove ${removedThemes.length} legacy theme(s).`);
    }

    const orphanAfter = dryRun
      ? 0
      : Number(
          (
            await ds.query<Array<{ c: string }>>(
              `SELECT count(*)::text AS c
               FROM tours t
               INNER JOIN tour_details td ON td.tour_id = t.id
               CROSS JOIN LATERAL jsonb_array_elements_text(
                 COALESCE(td.trip_details->'overview'->'tourThemeIds', '[]'::jsonb)
               ) AS theme_id
               WHERE t.tenant_id = $1
                 AND theme_id NOT IN (SELECT id::text FROM workspace_tour_themes WHERE workspace_id = $2)`,
              [tenant.id, tenant.id],
            )
          )[0]?.c ?? 0,
        );

    const report: DenaliThemeApplyReport = {
      timestamp: new Date().toISOString(),
      dryRun,
      workspaceId: tenant.id,
      removedThemes,
      addedThemes,
      remappedPresets,
      remappedTours,
      ghostValidation: {
        presetsSanitized,
        toursSanitized,
        warnings: ghostWarnings,
      },
      manualReview: {
        unmappedPresetThemeIds: [...unmappedPresetThemeIds],
        unmappedTourThemeIds: [...unmappedTourThemeIds],
        orphanThemeRefsAfterApply: orphanAfter,
      },
    };

    const block = `[Denali Theme Apply Phase 2]\n${JSON.stringify(report, null, 2)}\n`;
    fs.appendFileSync(logPath, block, "utf8");

    emitScriptInfo(`Report written to ${logPath}`);
    emitScriptInfo(
      `Remapped presets=${remappedPresets.length} tours=${remappedTours.length} ghostWarnings=${ghostWarnings.length} orphans=${orphanAfter}`,
    );

    const needsManual =
      unmappedPresetThemeIds.size > 0 ||
      unmappedTourThemeIds.size > 0 ||
      orphanAfter > 0;
    if (needsManual) {
      return 2;
    }
    if (ghostWarnings.length > 0) {
      return 1;
    }
    return 0;
  } finally {
    await ds.destroy();
  }
}

const logPath = resolveLogPathFromArgv(process.argv);
const dryRun = parseDryRun(process.argv);

denaliThemeApply({ logPath, dryRun })
  .then((code) => {
    if (code !== 0) {
      process.exitCode = code;
    }
  })
  .catch((error: unknown) => {
    process.exitCode = 1;
  });

/**
 * Denali Wizard QA — Phase 1: Theme check & ghost-field simulation (read-only).
 *
 * Dry-run before replacing workspace tour themes. Does not mutate the database.
 * Appends a JSON report to `map.log` at the repository root.
 *
 * ```bash
 * pnpm --filter @apps/api qa:denali:theme-dry-run
 * ```
 */
import fs from "node:fs";
import path from "node:path";
import { DataSource } from "typeorm";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { DENALI_SUBDOMAIN, DENALI_THEME_SEEDS } from "./denali-tenant.fixture";
import { DENALI_CONSOLIDATED_THEME_SEEDS } from "./denali-theme-migration.shared";
import { emitScriptInfo } from "./script-log";

const REPO_ROOT = path.resolve(__dirname, "../../../..");
const MAP_LOG = path.join(REPO_ROOT, "map.log");

type ThemeRow = {
  id: string;
  slug: string;
  name: string;
  description: string | null;
  form_profile: string;
  is_active: boolean;
  sort_order: number;
};

type DependentFieldIssue = {
  layer: "preset_defaults" | "preset_match" | "tour_trip_details";
  field: string;
  count: number;
  sampleIds?: string[];
};

function resolveLogPathFromArgv(argv: readonly string[]): string {
  for (const arg of argv) {
    if (arg.startsWith("--log=")) {
      return path.resolve(REPO_ROOT, arg.slice("--log=".length));
    }
  }
  return MAP_LOG;
}

export async function denaliThemeDryRun(logPath = MAP_LOG): Promise<void> {
  emitScriptInfo("=== Denali Wizard QA Dry Run: Phase 1 (themes + dependent fields) ===");

  const ds = new DataSource(createDataSourceOptionsFromEnv());
  await ds.initialize();

  try {
    const tenants = await ds.query<Array<{ id: string }>>(
      `SELECT id FROM tenants WHERE deleted_at IS NULL AND lower(trim(subdomain)) = lower(trim($1)) LIMIT 1`,
      [DENALI_SUBDOMAIN],
    );
    const tenant = tenants[0];
    if (!tenant) {
      throw new Error(`Tenant subdomain "${DENALI_SUBDOMAIN}" not found. Run provision:denali first.`);
    }

    const currentThemes = await ds.query<ThemeRow[]>(
      `SELECT id, slug, name, description, form_profile, is_active, sort_order
       FROM workspace_tour_themes
       WHERE workspace_id = $1
       ORDER BY sort_order ASC, name ASC`,
      [tenant.id],
    );

    emitScriptInfo(`Current themes (${currentThemes.length}): ${currentThemes.map((t) => t.slug).join(", ")}`);

    const simulatedRemoval = currentThemes.map((theme) => ({ ...theme, action: "REMOVE" as const }));
    const simulatedAddition = DENALI_CONSOLIDATED_THEME_SEEDS.map((theme) => ({
      ...theme,
      action: "ADD" as const,
    }));

    const fieldIssues: DependentFieldIssue[] = [];

    const presetMainTheme = await ds.query<Array<{ id: string }>>(
      `SELECT id FROM workspace_tour_creation_presets
       WHERE workspace_id = $1
         AND (
           (defaults->'programNature'->>'mainTourThemeId') IS NOT NULL
           OR match_main_tour_theme_id IS NOT NULL
         )`,
      [tenant.id],
    );
    if (presetMainTheme.length > 0) {
      fieldIssues.push({
        layer: "preset_defaults",
        field: "program.mainThemeId (programNature.mainTourThemeId / match_main_tour_theme_id)",
        count: presetMainTheme.length,
        sampleIds: presetMainTheme.slice(0, 5).map((r) => r.id),
      });
    }

    const presetDifficulty = await ds.query<Array<{ id: string }>>(
      `SELECT id FROM workspace_tour_creation_presets
       WHERE workspace_id = $1
         AND (defaults->'programNature'->>'difficultyLevel') IS NOT NULL`,
      [tenant.id],
    );
    if (presetDifficulty.length > 0) {
      fieldIssues.push({
        layer: "preset_defaults",
        field: "program.difficultyLevel (programNature.difficultyLevel)",
        count: presetDifficulty.length,
        sampleIds: presetDifficulty.slice(0, 5).map((r) => r.id),
      });
    }

    const presetHiking = await ds.query<Array<{ id: string }>>(
      `SELECT id FROM workspace_tour_creation_presets
       WHERE workspace_id = $1
         AND (defaults->'programNature'->>'hikingHoursApprox') IS NOT NULL`,
      [tenant.id],
    );
    if (presetHiking.length > 0) {
      fieldIssues.push({
        layer: "preset_defaults",
        field: "program.hikingHoursApprox (programNature.hikingHoursApprox)",
        count: presetHiking.length,
        sampleIds: presetHiking.slice(0, 5).map((r) => r.id),
      });
    }

    const themeIds = currentThemes.map((t) => t.id);
    if (themeIds.length > 0) {
      const orphanPresetMatch = await ds.query<Array<{ id: string; theme_id: string }>>(
        `SELECT id, match_main_tour_theme_id AS theme_id
         FROM workspace_tour_creation_presets
         WHERE workspace_id = $1 AND match_main_tour_theme_id = ANY($2::uuid[])`,
        [tenant.id, themeIds],
      );
      if (orphanPresetMatch.length > 0) {
        fieldIssues.push({
          layer: "preset_match",
          field: "match_main_tour_theme_id → existing theme UUID",
          count: orphanPresetMatch.length,
          sampleIds: orphanPresetMatch.slice(0, 5).map((r) => r.id),
        });
      }
    }

    const tourThemeRefs = await ds.query<Array<{ tour_id: string }>>(
      `SELECT t.id AS tour_id
       FROM tours t
       INNER JOIN tour_details td ON td.tour_id = t.id
       WHERE t.tenant_id = $1
         AND td.trip_details IS NOT NULL
         AND jsonb_array_length(COALESCE(td.trip_details->'overview'->'tourThemeIds', '[]'::jsonb)) > 0`,
      [tenant.id],
    );
    if (tourThemeRefs.length > 0) {
      fieldIssues.push({
        layer: "tour_trip_details",
        field: "overview.tourThemeIds (projection of program.mainThemeId)",
        count: tourThemeRefs.length,
        sampleIds: tourThemeRefs.slice(0, 5).map((r) => r.tour_id),
      });
    }

    const tourDifficulty = await ds.query<Array<{ tour_id: string }>>(
      `SELECT t.id AS tour_id
       FROM tours t
       INNER JOIN tour_details td ON td.tour_id = t.id
       WHERE t.tenant_id = $1
         AND (td.trip_details->'overview'->>'difficultyLevel') IS NOT NULL`,
      [tenant.id],
    );
    if (tourDifficulty.length > 0) {
      fieldIssues.push({
        layer: "tour_trip_details",
        field: "overview.difficultyLevel",
        count: tourDifficulty.length,
        sampleIds: tourDifficulty.slice(0, 5).map((r) => r.tour_id),
      });
    }

    const fixtureSlugs = new Set<string>(DENALI_THEME_SEEDS.map((s) => s.slug));
    const missingFixture = DENALI_THEME_SEEDS.filter(
      (spec) => !currentThemes.some((row) => row.slug === spec.slug && row.is_active),
    );
    const extraThemes = currentThemes.filter((row) => !fixtureSlugs.has(row.slug));

    const dryRunReport = {
      timestamp: new Date().toISOString(),
      workspaceId: tenant.id,
      subdomain: DENALI_SUBDOMAIN,
      currentThemes: currentThemes.map((t) => ({
        id: t.id,
        slug: t.slug,
        name: t.name,
        formProfile: t.form_profile,
        isActive: t.is_active,
      })),
      fixtureExpectation: DENALI_THEME_SEEDS.map((s) => s.slug),
      fixtureMissing: missingFixture.map((s) => s.slug),
      themesNotInFixture: extraThemes.map((t) => t.slug),
      simulatedRemoval,
      simulatedAddition,
      dependentFieldIssues: fieldIssues,
      ghostClearingNote:
        "After theme removal, re-run wizard invariant tests (denaliGhostState.spec.ts) and remap preset/tour theme UUIDs before publish.",
    };

    const reportBlock = `[Denali Theme Dry Run Phase 1]\n${JSON.stringify(dryRunReport, null, 2)}\n`;
    fs.appendFileSync(logPath, reportBlock, "utf8");

    for (const issue of fieldIssues) {
      emitScriptInfo(
        `WARN ${issue.field}: ${issue.count} row(s) in ${issue.layer} — verify ghost clearing / remap before apply`,
      );
    }

    emitScriptInfo(`Dry run complete. Report appended to ${logPath}`);
    if (fieldIssues.length > 0) {
      process.exitCode = 2;
    }
  } finally {
    await ds.destroy();
  }
}

const logPath = resolveLogPathFromArgv(process.argv);
denaliThemeDryRun(logPath).catch((error: unknown) => {
  process.exitCode = 1;
});

