});

import { createHmac } from "node:crypto";
import { readFile } from "node:fs/promises";
import { join } from "node:path";
import { DataSource } from "typeorm";
import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { TourEntity } from "../modules/tours/entities/tour.entity";
import { RegistrationEntity } from "../modules/registrations/registration.entity";
import { PaymentEntity } from "../modules/payments/entities/payment.entity";
import { UserEntity } from "../modules/identity/entities/user.entity";
import { UserTenantEntity } from "../modules/identity/entities/user-tenant.entity";
import { TenantEntity } from "../modules/identity/entities/tenant.entity";

type SeedOutput = {
  tenantId: string;
  tenantSubdomain: string;
  tenantName: string;
  user: {
    id: string;
    email: string;
    phone: string;
    password: string;
    role: string;
  };
  tours: Array<{
    id: string;
    title: string;
    totalCapacity: number;
    acceptedCount: number;
  }>;
};

type FlowResult = {
  name: string;
  passed: boolean;
  details: string;
};

function requireEnv(name: string): string {
  const value = process.env[name];
  if (!value || value.trim() === "") {
    throw new Error(`Missing required env: ${name}`);
  }
  return value;
}

function signPaymentsWebhookBody(rawBody: string, secret: string): {
  timestamp: string;
  signature: string;
} {
  const timestamp = String(Math.floor(Date.now() / 1000));
  const signature = createHmac("sha256", secret)
    .update(Buffer.concat([Buffer.from(`${timestamp}.`, "utf8"), Buffer.from(rawBody, "utf8")]))
    .digest("hex");
  return { timestamp, signature };
}

async function requestJson<T>(
  baseUrl: string,
  path: string,
  init?: RequestInit
): Promise<{ status: number; body: T }> {
  const res = await fetch(`${baseUrl}${path}`, init);
  const text = await res.text();
  const body = text ? (JSON.parse(text) as T) : ({} as T);
  return { status: res.status, body };
}

async function run(): Promise<void> {
  const baseUrl = process.env.BASE_URL ?? "http://localhost:3000";
  const webhookSigningSecret = requireEnv("PAYMENTS_WEBHOOK_SIGNING_SECRET");
  const seedPath = join(process.cwd(), ".seed-output.json");
  const seed = JSON.parse(await readFile(seedPath, "utf8")) as SeedOutput;
  if (!seed.tenantSubdomain?.trim()) {
    throw new Error(
      ".seed-output.json is missing tenantSubdomain; rerun apps/api seed to regenerate output."
    );
  }

  const results: FlowResult[] = [];
  const flow = (name: string, passed: boolean, details: string) => {
    results.push({ name, passed, details });
  };

  let token = "";
  let selectedTourId = seed.tours[0]?.id ?? "";
  let registrationId = "";
  let providerPaymentId = `freeze-pay-${Date.now()}`;
  const uniqueSuffix = String(Date.now()).slice(-6);
  const participantPhone = `+98912${uniqueSuffix}`;

  try {
    const tenantRoot = process.env.TENANT_ROOT_DOMAIN?.trim() || "localhost";
    const loginHost =
      tenantRoot === "localhost"
        ? `${seed.tenantSubdomain}.localhost`
        : `${seed.tenantSubdomain}.${tenantRoot}`;

    const auth = await requestJson<{
      session_token?: string;
      user_id?: string;
      tenant_id?: string;
    }>(baseUrl, "/api/v2/auth/web/session/otp", {
      method: "POST",
      headers: { "Content-Type": "application/json", Host: loginHost },
      body: JSON.stringify({
        phone: seed.user.phone,
        otp: "1234"
      })
    });
    token = auth.body.session_token ?? "";
    flow(
      "FLOW 1: AUTH (web session login)",
      auth.status === 200 && token.length > 0,
      `status=${auth.status}, hasToken=${token.length > 0}`
    );

    const tours = await requestJson<{ items: Array<{ id: string; title: string }> }>(
      baseUrl,
      "/api/v2/tours",
      {
        method: "GET",
        headers: { Authorization: `Bearer ${token}` }
      }
    );
    const tourItems = Array.isArray(tours.body?.items) ? tours.body.items : [];
    const seededTitleSet = new Set(seed.tours.map((t) => t.title));
    const matchedSeededTours = tourItems.filter((t) => seededTitleSet.has(t.title));
    if (matchedSeededTours.length > 0) {
      selectedTourId = matchedSeededTours[0].id;
    }
    flow(
      "FLOW 2: LIST TOURS",
      tours.status === 200 && matchedSeededTours.length === 3,
      `status=${tours.status}, seededToursFound=${matchedSeededTours.length}`
    );

    const reg = await requestJson<{ id?: string }>(baseUrl, "/api/v2/registrations", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${token}`,
        "Idempotency-Key": `freeze-reg-${Date.now()}`
      },
      body: JSON.stringify({
        tenantId: seed.tenantId,
        tourId: selectedTourId,
        participantFullName: `Freeze Validation User ${uniqueSuffix}`,
        participantContactPhone: participantPhone,
        transportMode: "group_vehicle",
        entryMode: "web"
      })
    });
    registrationId = reg.body.id ?? "";
    flow(
      "FLOW 3: CREATE REGISTRATION",
      reg.status === 201 && registrationId.length > 0,
      `status=${reg.status}, registrationId=${registrationId || "none"}`
    );

    const idempotencyKey = `freeze-pay-intent-${Date.now()}`;
    let paymentIntentStatus = 0;
    if (!registrationId) {
      flow(
        "FLOW 4: PAYMENT INTENT",
        false,
        "skipped because registration was not created"
      );
    } else {
      const paymentIntent = await requestJson<{
        id?: string;
        providerPaymentId?: string | null;
      }>(baseUrl, "/api/v2/payments/intent", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
          "Idempotency-Key": idempotencyKey
        },
        body: JSON.stringify({
          registrationId,
          amount: 100,
          currency: "IRR",
          provider: "mock_provider",
          providerPaymentId
        })
      });
      paymentIntentStatus = paymentIntent.status;
      providerPaymentId = paymentIntent.body.providerPaymentId ?? providerPaymentId;
      flow(
        "FLOW 4: PAYMENT INTENT",
        paymentIntent.status === 201 && providerPaymentId.length > 0,
        `status=${paymentIntent.status}, providerPaymentId=${providerPaymentId}`
      );
    }

    const webhookBody = JSON.stringify({
      tenant_id: seed.tenantId,
      providerEventId: `freeze-webhook-${Date.now()}`,
      providerPaymentId,
      status: "Paid"
    });
    const whSig = signPaymentsWebhookBody(webhookBody, webhookSigningSecret);
    const webhook = await requestJson<{ ok?: boolean }>(baseUrl, "/internal/payments/webhook", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "x-payments-webhook-timestamp": whSig.timestamp,
        "x-payments-webhook-signature": whSig.signature
      },
      body: webhookBody
    });
    flow(
      "FLOW 5: WEBHOOK SIMULATION",
      webhook.status === 200 && webhook.body.ok === true,
      `status=${webhook.status}, ok=${String(webhook.body.ok)}`
    );

    if (!registrationId || paymentIntentStatus !== 201) {
      flow(
        "FLOW 6: IDEMPOTENCY REPLAY",
        false,
        "skipped because initial payment intent was not successful"
      );
    } else {
      const paymentReplay = await requestJson<{
        id?: string;
        providerPaymentId?: string | null;
      }>(baseUrl, "/api/v2/payments/intent", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
          "Idempotency-Key": idempotencyKey
        },
        body: JSON.stringify({
          registrationId,
          amount: 100,
          currency: "IRR",
          provider: "mock_provider",
          providerPaymentId
        })
      });
      flow(
        "FLOW 6: IDEMPOTENCY REPLAY",
        (paymentReplay.status === 200 || paymentReplay.status === 201) &&
          paymentReplay.body.providerPaymentId === providerPaymentId,
        `status=${paymentReplay.status}, providerPaymentId=${paymentReplay.body.providerPaymentId ?? "none"}`
      );
    }

    const dataSource = new DataSource({
      ...createDataSourceOptionsFromEnv(),
      entities: [
        UserEntity,
        UserTenantEntity,
        TenantEntity,
        TourEntity,
        RegistrationEntity,
        PaymentEntity
      ]
    });
    await dataSource.initialize();
    try {
      const user = await dataSource.getRepository(UserEntity).findOne({
        where: { id: seed.user.id }
      });
      const registration = registrationId
        ? await dataSource.getRepository(RegistrationEntity).findOne({
            where: { id: registrationId }
          })
        : null;
      const payment = providerPaymentId
        ? await dataSource.getRepository(PaymentEntity).findOne({
            where: { providerPaymentId }
          })
        : null;
      const tour = await dataSource.getRepository(TourEntity).findOne({
        where: { id: selectedTourId }
      });
      const paymentRowsForRegistration = registrationId
        ? await dataSource.getRepository(PaymentEntity).count({
            where: { registrationId }
          })
        : 0;

      const finalPass =
        Boolean(user) &&
        registration?.status === "AcceptedPaid" &&
        payment?.status === "Paid" &&
        paymentRowsForRegistration === 1 &&
        typeof tour?.acceptedCount === "number";

      flow(
        "FLOW 7: FINAL VERIFICATION (DB/API)",
        finalPass,
        `registrationStatus=${registration?.status ?? "none"}, paymentStatus=${payment?.status ?? "none"}, paymentRowsForRegistration=${paymentRowsForRegistration}, tourAcceptedCount=${tour?.acceptedCount ?? "none"}`
      );

      for (const item of results) {
        void item;
      }

      void { user, registration, payment, tour };
    } finally {
      await dataSource.destroy();
    }
  } catch (error: unknown) {
    const message = error instanceof Error ? error.stack ?? error.message : String(error);
    flow("UNHANDLED ERROR", false, message);
    for (const item of results) {
      void item;
    }
    process.exitCode = 1;
    return;
  }

  const hasFailure = results.some((item) => !item.passed);
  if (hasFailure) {
    process.exitCode = 1;
  }
}

run().catch((error: unknown) => {
  const message = error instanceof Error ? error.stack ?? error.message : String(error);
  process.exitCode = 1;
});

/**
 * One-off migration: legacy `tripDetails.overview.tourTheme` string tags →
 * `workspace_tour_themes` rows and `overview.tourThemeIds`.
 *
 * Usage:
 *   pnpm --filter @apps/api migrate:tour-theme-tags
 *   pnpm --filter @apps/api migrate:tour-theme-tags -- --dry-run
 */
import { createHash } from "node:crypto";
import { DataSource } from "typeorm";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { emitScriptInfo } from "./script-log";

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;

function normalizeThemeKey(raw: string): string {
  return raw.trim().toLowerCase();
}

function isNonEmptyStringTag(s: unknown): s is string {
  return typeof s === "string" && normalizeThemeKey(s).length > 0;
}

/** Trim + cap length for `workspace_tour_themes.name` (varchar 120). */
function canonicalDisplayName(firstTrimmed: string): string {
  const t = firstTrimmed.trim();
  if (t.length <= 120) {
    return t;
  }
  return `${t.slice(0, 117)}...`;
}

/**
 * ASCII-ish kebab slug from display name. Falls back to `legacy-<hex>` when empty
 * (e.g. non-Latin-only labels).
 */
function baseSlugFromName(displayName: string, normKey: string): string {
  const lower = displayName.trim().toLowerCase();
  const slug = lower
    .normalize("NFD")
    .replace(/\p{M}/gu, "")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 120);
  if (slug.length > 0) {
    return slug;
  }
  const h = createHash("sha256").update(normKey).digest("hex").slice(0, 14);
  return `legacy-${h}`;
}

function uniqueSlug(
  base: string,
  workspaceTaken: Set<string>,
  usedInBatch: Set<string>,
): string {
  const root = base.slice(0, 120);
  let candidate = root;
  let n = 2;
  while (workspaceTaken.has(candidate) || usedInBatch.has(candidate)) {
    const suffix = `-${n}`;
    n += 1;
    candidate = `${root.slice(0, Math.max(0, 120 - suffix.length))}${suffix}`;
  }
  usedInBatch.add(candidate);
  return candidate;
}

function filterValidUuid(ids: unknown): string[] {
  if (!Array.isArray(ids)) {
    return [];
  }
  const out: string[] = [];
  const seen = new Set<string>();
  for (const x of ids) {
    if (typeof x !== "string") {
      continue;
    }
    const t = x.trim();
    if (!UUID_RE.test(t) || seen.has(t)) {
      continue;
    }
    seen.add(t);
    out.push(t);
  }
  return out;
}

function dedupeIdsPreserveOrder(ids: string[]): string[] {
  const out: string[] = [];
  const seen = new Set<string>();
  for (const id of ids) {
    if (seen.has(id)) {
      continue;
    }
    seen.add(id);
    out.push(id);
  }
  return out;
}

type TourDetailsRow = {
  tourDetailsId: string;
  tourId: string;
  tenantId: string;
  tripDetails: Record<string, unknown>;
};

function rowHasStringTourThemes(row: TourDetailsRow): boolean {
  const overview = row.tripDetails?.overview;
  if (!overview || typeof overview !== "object" || Array.isArray(overview)) {
    return false;
  }
  const tourTheme = (overview as { tourTheme?: unknown }).tourTheme;
  if (!Array.isArray(tourTheme)) {
    return false;
  }
  return tourTheme.some((t) => isNonEmptyStringTag(t));
}

async function main(): Promise<void> {
  const dryRun = process.argv.includes("--dry-run");
  const dataSource = new DataSource(createDataSourceOptionsFromEnv());
  await dataSource.initialize();
  try {
    const rows = await dataSource.query<TourDetailsRow[]>(`
      SELECT td.id AS "tourDetailsId",
             td.tour_id AS "tourId",
             t.tenant_id AS "tenantId",
             td.trip_details AS "tripDetails"
      FROM tour_details td
      INNER JOIN tours t ON t.id = td.tour_id
      WHERE t.deleted_at IS NULL
        AND td.trip_details IS NOT NULL
        AND jsonb_typeof(td.trip_details->'overview'->'tourTheme') = 'array'
        AND jsonb_array_length(COALESCE(td.trip_details->'overview'->'tourTheme', '[]'::jsonb)) > 0
    `);

    const globalNormKeys = new Set<string>();
    for (const row of rows) {
      const overview = row.tripDetails?.overview;
      if (!overview || typeof overview !== "object" || Array.isArray(overview)) {
        continue;
      }
      const tourTheme = (overview as { tourTheme?: unknown }).tourTheme;
      if (!Array.isArray(tourTheme)) {
        continue;
      }
      for (const tag of tourTheme) {
        if (!isNonEmptyStringTag(tag)) {
          continue;
        }
        globalNormKeys.add(normalizeThemeKey(tag));
      }
    }

    const byWorkspace = new Map<string, TourDetailsRow[]>();
    for (const row of rows) {
      const list = byWorkspace.get(row.tenantId) ?? [];
      list.push(row);
      byWorkspace.set(row.tenantId, list);
    }

    let themesInserted = 0;
    let themesMatchedExistingCatalog = 0;
    let toursMigrated = 0;

    for (const [workspaceId, wsRows] of byWorkspace) {
      const firstLabel = new Map<string, string>();
      for (const row of wsRows) {
        const overview = row.tripDetails?.overview;
        if (!overview || typeof overview !== "object" || Array.isArray(overview)) {
          continue;
        }
        const tourTheme = (overview as { tourTheme?: unknown }).tourTheme;
        if (!Array.isArray(tourTheme)) {
          continue;
        }
        for (const tag of tourTheme) {
          if (!isNonEmptyStringTag(tag)) {
            continue;
          }
          const nk = normalizeThemeKey(tag);
          const trimmed = tag.trim();
          if (!firstLabel.has(nk)) {
            firstLabel.set(nk, trimmed);
          }
        }
      }

      const slugRows = (await dataSource.query(
        `SELECT id, slug FROM workspace_tour_themes WHERE workspace_id = $1`,
        [workspaceId],
      )) as { id: string; slug: string }[];
      const existingSlugToId = new Map(slugRows.map((r) => [r.slug, r.id]));
      const workspaceTaken = new Set<string>(slugRows.map((r) => r.slug));
      const batchSlugUsed = new Set<string>();
      /** Prevents two normKeys that share the same kebab `base` from mapping to the same theme id. */
      const baseSlugSlotUsed = new Set<string>();

      const normKeyToThemeId = new Map<string, string>();
      const sortedKeys = [...firstLabel.keys()].sort((a, b) => a.localeCompare(b));

      const maxRow = (await dataSource.query(
        `SELECT MAX(sort_order)::text AS m FROM workspace_tour_themes WHERE workspace_id = $1`,
        [workspaceId],
      )) as { m: string | null }[];
      const maxParsed = maxRow[0]?.m != null ? Number.parseInt(maxRow[0].m, 10) : 0;
      let nextSort = Number.isFinite(maxParsed) ? maxParsed + 1 : 0;

      for (const nk of sortedKeys) {
        const label = firstLabel.get(nk)!;
        const displayName = canonicalDisplayName(label);
        const baseSlug = baseSlugFromName(displayName, nk);

        if (existingSlugToId.has(baseSlug) && !baseSlugSlotUsed.has(baseSlug)) {
          const id = existingSlugToId.get(baseSlug)!;
          normKeyToThemeId.set(nk, id);
          baseSlugSlotUsed.add(baseSlug);
          themesMatchedExistingCatalog += 1;
          continue;
        }

        const slug = uniqueSlug(baseSlug, workspaceTaken, batchSlugUsed);
        workspaceTaken.add(slug);

        const existing = (await dataSource.query(
          `SELECT id FROM workspace_tour_themes WHERE workspace_id = $1 AND slug = $2 LIMIT 1`,
          [workspaceId, slug],
        )) as { id: string }[];
        if (existing.length > 0) {
          normKeyToThemeId.set(nk, existing[0]!.id);
          if (slug === baseSlug) {
            baseSlugSlotUsed.add(baseSlug);
          }
          themesMatchedExistingCatalog += 1;
          continue;
        }

        if (dryRun) {
          if (slug === baseSlug) {
            baseSlugSlotUsed.add(baseSlug);
          }
          themesInserted += 1;
          continue;
        }

        const inserted = (await dataSource.query(
          `
          INSERT INTO workspace_tour_themes
            (workspace_id, name, slug, description, is_active, sort_order)
          VALUES ($1, $2, $3, NULL, true, $4)
          RETURNING id
          `,
          [workspaceId, displayName, slug, nextSort],
        )) as { id: string }[];
        nextSort += 1;
        const id = inserted[0]!.id;
        normKeyToThemeId.set(nk, id);
        existingSlugToId.set(slug, id);
        if (slug === baseSlug) {
          baseSlugSlotUsed.add(baseSlug);
        }
        themesInserted += 1;
      }

      if (dryRun) {
        toursMigrated += wsRows.filter(rowHasStringTourThemes).length;
        continue;
      }

      for (const row of wsRows) {
        const trip = { ...row.tripDetails } as Record<string, unknown>;
        const overviewRaw = trip.overview;
        if (!overviewRaw || typeof overviewRaw !== "object" || Array.isArray(overviewRaw)) {
          continue;
        }
        const overview = { ...(overviewRaw as Record<string, unknown>) };
        const tourTheme = overview.tourTheme;
        if (!Array.isArray(tourTheme)) {
          continue;
        }
        const stringTags = tourTheme.filter(isNonEmptyStringTag);
        if (stringTags.length === 0) {
          continue;
        }
        const mappedIds: string[] = [];
        for (const tag of stringTags) {
          const nk = normalizeThemeKey(tag);
          const id = normKeyToThemeId.get(nk);
          if (id) {
            mappedIds.push(id);
          }
        }
        const existingIds = filterValidUuid(overview.tourThemeIds);
        const merged = dedupeIdsPreserveOrder([...mappedIds, ...existingIds]);
        overview.tourThemeIds = merged.length > 0 ? merged : undefined;
        delete overview.tourTheme;
        if (Object.keys(overview).length === 0) {
          delete trip.overview;
        } else {
          trip.overview = overview;
        }

        await dataSource.query(`UPDATE tour_details SET trip_details = $1::jsonb WHERE id = $2`, [
          JSON.stringify(trip),
          row.tourDetailsId,
        ]);
        toursMigrated += 1;
      }
    }

    emitScriptInfo(
      JSON.stringify(
        {
          dryRun,
          uniqueThemeStrings: globalNormKeys.size,
          workspacesAffected: byWorkspace.size,
          themeRowsInserted: themesInserted,
          themeRowsMatchedExistingCatalogSlug: themesMatchedExistingCatalog,
          toursMigrated,
        },
        null,
        2,
      ),
    );
  } finally {
    await dataSource.destroy();
  }
}

main().catch((error: unknown) => {
  const message = error instanceof Error ? error.stack ?? error.message : String(error);
  process.exitCode = 1;
});

/**
 * Dev probe: OTP session + POST /api/v2/tours for a provisioned workspace slug.
 *
 *   pnpm --filter @apps/api probe:tour-create -- --slug=denali
 *   API_BASE_URL=http://127.0.0.1:3001 pnpm --filter @apps/api probe:tour-create -- --slug=urban-demo
 *
 * Requires API running with dev static OTP (1234) and matching owner phone on the user row.
 */
import { randomUUID } from "node:crypto";

import { DENALI_OWNER_PHONE, DENALI_SUBDOMAIN } from "./denali-tenant.fixture";
import { DataSource } from "typeorm";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { WorkspaceDestinationEntity } from "../modules/settings-locations/entities/workspace-destination.entity";
import { emitScriptInfo } from "./script-log";
import { MIX_DEMO_OWNER_PHONE, MIX_DEMO_SUBDOMAIN } from "./mix-demo-tenant.fixture";
import { URBAN_DEMO_OWNER_PHONE, URBAN_DEMO_SUBDOMAIN } from "./urban-demo-tenant.fixture";
import { resolveTenantSlugFromArgv } from "./verify-workspace-tenant";

const DEV_OTP = "1234";

const SLUG_OWNER_PHONE: Record<string, string> = {
  [DENALI_SUBDOMAIN]: DENALI_OWNER_PHONE,
  [URBAN_DEMO_SUBDOMAIN]: URBAN_DEMO_OWNER_PHONE,
  [MIX_DEMO_SUBDOMAIN]: MIX_DEMO_OWNER_PHONE,
};

function workspaceBaseUrl(slug: string): string {
  const fromEnv = process.env.API_BASE_URL?.trim();
  if (fromEnv) {
    return fromEnv.replace(/\/$/, "");
  }
  const port = process.env.PORT?.trim() || "3001";
  return `http://${slug}.localhost:${port}`;
}

async function fetchJson(
  url: string,
  init: RequestInit = {},
): Promise<{ status: number; body: unknown }> {
  const headers = new Headers(init.headers);
  headers.set("Content-Type", "application/json");
  const res = await fetch(url, { ...init, headers });
  let body: unknown;
  const text = await res.text();
  try {
    body = text ? JSON.parse(text) : null;
  } catch {
    body = text;
  }
  return { status: res.status, body };
}

export async function probeWorkspaceTourCreate(slug: string): Promise<void> {
  const phone = SLUG_OWNER_PHONE[slug];
  if (!phone) {
    throw new Error(
      `probe:tour-create: no owner phone mapped for "${slug}". Add to SLUG_OWNER_PHONE or pass a known QA slug.`,
    );
  }

  const base = workspaceBaseUrl(slug);

  const session = await fetchJson(`${base}/api/v2/auth/web/session/otp`, {
    method: "POST",
    body: JSON.stringify({ phone, otp: DEV_OTP }),
  });
  if (session.status !== 200) {
    throw new Error(
      `OTP session failed (${session.status}): ${JSON.stringify(session.body)}. Is API up at ${base}? AUTH_ALLOW_DEV_STATIC_OTP enabled?`,
    );
  }
  const token = (session.body as { session_token?: string }).session_token;
  if (!token) {
    throw new Error(`OTP response missing session_token: ${JSON.stringify(session.body)}`);
  }

  const title = `Probe ${slug} ${randomUUID().slice(0, 8)} TenChars`;
  const body =
    slug === DENALI_SUBDOMAIN
      ? await buildDenaliProbeCreateBody(title)
      : {
          title,
          total_capacity: 10,
          lifecycle_status: "Draft",
          transportModes: [],
        };

  const tour = await fetchJson(`${base}/api/v2/tours`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${token}`,
      "Idempotency-Key": randomUUID(),
    },
    body: JSON.stringify(body),
  });

  if (tour.status !== 201) {
    throw new Error(`POST /tours failed (${tour.status}): ${JSON.stringify(tour.body)}`);
  }

  const tourId = (tour.body as { id?: string }).id;
  emitScriptInfo(`✓ ${slug}: created tour id=${tourId} title="${title}"`);
}

async function buildDenaliProbeCreateBody(title: string): Promise<Record<string, unknown>> {
  const ds = new DataSource({
    ...createDataSourceOptionsFromEnv(),
    entities: [WorkspaceDestinationEntity],
  });
  await ds.initialize();
  try {
    const dest = await ds.getRepository(WorkspaceDestinationEntity).findOne({
      where: { isActive: true },
      order: { sortOrder: "ASC" },
    });
    const destinationId = dest?.id;
    if (!destinationId) {
      throw new Error("Denali probe: no active destination — run provision:denali first.");
    }
    return {
      title,
      total_capacity: 12,
      lifecycle_status: "Draft",
      tourType: "mountain",
      destinationId,
      price: 100_000,
      requiresPayment: true,
      formProfile: "denali_pilot",
      transportModes: ["bus"],
      tripDetails: {
        overview: {
          denaliTourKind: "mountain_day",
          shortIntro: "Denali probe tour",
        },
        logistics: {
          departureDate: "2026-09-01",
          departureMeetingTime: "08:00",
          primaryTransportMode: "bus",
          groupSizeMax: 12,
        },
        participation: {
          minimumAge: 18,
          fitnessLevel: "moderate",
          experienceLevel: "basic",
          sportsInsuranceRequired: true,
        },
        policies: {
          cancellationPolicy: "Probe cancellation policy text.",
        },
      },
    };
  } finally {
    await ds.destroy();
  }
}

const slug = resolveTenantSlugFromArgv(process.argv.slice(2));
probeWorkspaceTourCreate(slug).catch((e: unknown) => {
  process.exit(1);
});

/**
 * Idempotent provision for workspace tenant **Denali** (subdomain `denali`).
 *
 * - Tenant + `form_builder` / `finance` modules (Tour Create Wizard at `/tours/new`)
 * - Default tour themes: mountain_outdoor, nature_trip (day trips), cinema_event (short sessions)
 * - Workspace tour-creation presets aligned to those profiles
 * - Global owner user (requested id `01234567890` → fixture UUID below)
 * - Minimal region + destination when catalog is empty
 *
 * Run (from repo root):
 *   pnpm --filter @apps/api provision:denali
 *
 * Optional follow-ups:
 *   ALLOW_DENALI_SEED=1 pnpm --filter @apps/api seed:denali-locations
 *   ALLOW_DENALI_SEED=1 pnpm --filter @apps/api seed:denali-equipment
 */
import * as argon2 from "argon2";
import { DataSource, IsNull, Repository } from "typeorm";

import type { DenaliTourKind, TourFormProfile } from "@repo/types";
import {
  DENALI_OWNER_EMAIL,
  DENALI_OWNER_NATIONAL_ID,
  DENALI_OWNER_REQUESTED_ID,
