  const regionRepo = dataSource.getRepository(WorkspaceRegionEntity);
  const region = await regionRepo.save(
    regionRepo.create({
      tenantId,
      name: "Denali — پیش‌فرض",
      country: "IR",
      sortOrder: 0,
      isActive: true,
    }),
  );
  const destination = await destRepo.save(
    destRepo.create({
      tenantId,
      regionId: region.id,
      name: "مقصد پیش‌فرض دنالی",
      type: "شهر",
