/**
 * Wipes **all** Denali workspace data (tours + catalog + bookings) while keeping:
 * - the `denali` tenant row
 * - the canonical Denali owner user + owner membership
 *
 * Requires `ALLOW_DENALI_RESET=1`. In production also set `ALLOW_DENALI_RESET=true`.
 *
 * ```bash
 * ALLOW_DENALI_RESET=1 pnpm --filter @apps/api reset:denali
 * ALLOW_DENALI_RESET=1 pnpm --filter @apps/api reset:denali -- --reprovision
 * ```
 */
import { DataSource } from "typeorm";

import { createDataSourceOptionsFromEnv } from "../database/database.config";
import {
  DENALI_OWNER_USER_ID,
  DENALI_SUBDOMAIN,
} from "./denali-tenant.fixture";
import { emitScriptInfo } from "./script-log";
import { provisionDenaliTenant } from "./provision-denali-tenant";

type CountRow = { c: string };

function fail(message: string): never {
  throw new Error(message);
}

function parseReprovisionFlag(): boolean {
  return process.argv.includes("--reprovision");
}

async function deleteCount(
  ds: DataSource,
  label: string,
  sql: string,
  params: unknown[],
): Promise<number> {
  const counted = await ds.query<CountRow[]>(
    `WITH d AS (${sql} RETURNING 1) SELECT count(*)::text AS c FROM d`,
    params,
  );
  const n = Number(counted[0]?.c ?? 0);
  emitScriptInfo(`  ${label}: ${n}`);
  return n;
}

export type DenaliResetSummary = {
  tenantId: string;
  subdomain: string;
  ownerUserId: string;
  deleted: Record<string, number>;
  reprovisioned: boolean;
};

export async function resetDenaliWorkspace(options?: { reprovision?: boolean }): Promise<DenaliResetSummary> {
  if (process.env.ALLOW_DENALI_RESET?.trim() !== "1") {
    fail(
      "reset-denali-workspace: set ALLOW_DENALI_RESET=1 to run. This deletes tours, catalog, registrations, and non-owner members for tenant denali.",
    );
  }
  if (process.env.NODE_ENV === "production" && process.env.ALLOW_DENALI_RESET !== "true") {
    fail(
      "reset-denali-workspace: refusing production. Set ALLOW_DENALI_RESET=true after explicit review.",
    );
  }

  const ds = new DataSource({
    ...createDataSourceOptionsFromEnv(),
    entities: [],
  });

  await ds.initialize();
  const deleted: Record<string, number> = {};
  let summary: DenaliResetSummary | undefined;

  try {
    const tenantRows = await ds.query<Array<{ id: string }>>(
      `SELECT id FROM tenants WHERE subdomain = $1 AND deleted_at IS NULL LIMIT 1`,
      [DENALI_SUBDOMAIN],
    );
    const tenantId = tenantRows[0]?.id;
    if (!tenantId) {
      fail(`reset-denali-workspace: tenant subdomain "${DENALI_SUBDOMAIN}" not found. Run provision:denali first.`);
    }
    const workspaceId = tenantId;

    emitScriptInfo(`=== Denali workspace reset (tenant_id=${tenantId}) ===`);

    await ds.query("BEGIN");

    try {
      const findings = await ds.query<CountRow[]>(
        `WITH d AS (
          DELETE FROM reconciliation_findings WHERE tenant_id = $1
          RETURNING id
        ) SELECT count(*)::text AS c FROM d`,
        [tenantId],
      );
      deleted.reconciliation_findings = Number(findings[0]?.c ?? 0);
      emitScriptInfo(`  reconciliation_findings: ${deleted.reconciliation_findings}`);

      const jobs = await ds.query<CountRow[]>(
        `WITH d AS (
          DELETE FROM reconciliation_jobs WHERE tenant_id = $1
          RETURNING id
        ) SELECT count(*)::text AS c FROM d`,
        [tenantId],
      );
      deleted.reconciliation_jobs = Number(jobs[0]?.c ?? 0);
      emitScriptInfo(`  reconciliation_jobs: ${deleted.reconciliation_jobs}`);

      deleted.payment_receipts = await deleteCount(
        ds,
        "payment_receipts",
        `DELETE FROM payment_receipts WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.payments = await deleteCount(
        ds,
        "payments",
        `DELETE FROM payments WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.booking_price_snapshots = await deleteCount(
        ds,
        "booking_price_snapshots",
        `DELETE FROM booking_price_snapshots WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.payment_gateway_idempotency = await deleteCount(
        ds,
        "payment_gateway_idempotency",
        `DELETE FROM payment_gateway_idempotency WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.waitlist_items = await deleteCount(
        ds,
        "waitlist_items",
        `DELETE FROM waitlist_items WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.registrations = await deleteCount(
        ds,
        "registrations",
        `DELETE FROM registrations WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.tour_details = await deleteCount(
        ds,
        "tour_details",
        `DELETE FROM tour_details WHERE tour_id IN (SELECT id FROM tours WHERE tenant_id = $1)`,
        [tenantId],
      );

      deleted.tours = await deleteCount(
        ds,
        "tours",
        `DELETE FROM tours WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.tour_departures = await deleteCount(
        ds,
        "tour_departures",
        `DELETE FROM tour_departures WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.tour_products = await deleteCount(
        ds,
        "tour_products",
        `DELETE FROM tour_products WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.workspace_tour_wizard_templates = await deleteCount(
        ds,
        "workspace_tour_wizard_templates",
        `DELETE FROM workspace_tour_wizard_templates WHERE workspace_id = $1`,
        [workspaceId],
      );

      deleted.workspace_tour_creation_presets = await deleteCount(
        ds,
        "workspace_tour_creation_presets",
        `DELETE FROM workspace_tour_creation_presets WHERE workspace_id = $1`,
        [workspaceId],
      );

      deleted.workspace_tour_themes = await deleteCount(
        ds,
        "workspace_tour_themes",
        `DELETE FROM workspace_tour_themes WHERE workspace_id = $1`,
        [workspaceId],
      );

      deleted.workspace_equipment_items = await deleteCount(
        ds,
        "workspace_equipment_items",
        `DELETE FROM workspace_equipment_items WHERE workspace_id = $1`,
        [workspaceId],
      );

      deleted.workspace_destinations = await deleteCount(
        ds,
        "workspace_destinations",
        `DELETE FROM workspace_destinations WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.workspace_regions = await deleteCount(
        ds,
        "workspace_regions",
        `DELETE FROM workspace_regions WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.workspace_guide_languages = await deleteCount(
        ds,
        "workspace_guide_languages",
        `DELETE FROM workspace_guide_languages WHERE workspace_id = $1`,
        [workspaceId],
      );

      deleted.workspace_invites = await deleteCount(
        ds,
        "workspace_invites",
        `DELETE FROM workspace_invites WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.idempotency_keys = await deleteCount(
        ds,
        "idempotency_keys",
        `DELETE FROM idempotency_keys WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.outbox_events = await deleteCount(
        ds,
        "outbox_events",
        `DELETE FROM outbox_events WHERE tenant_id = $1`,
        [tenantId],
      );

      emitScriptInfo("  tenant_audit_events: skipped (append-only table)");
      deleted.tenant_audit_events = 0;

      deleted.tenant_usage_daily = await deleteCount(
        ds,
        "tenant_usage_daily",
        `DELETE FROM tenant_usage_daily WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.emergency_contacts = await deleteCount(
        ds,
        "emergency_contacts",
        `DELETE FROM emergency_contacts WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.medical_profiles = await deleteCount(
        ds,
        "medical_profiles",
        `DELETE FROM medical_profiles WHERE tenant_id = $1`,
        [tenantId],
      );

      deleted.user_role_audit = await deleteCount(
        ds,
        "user_role_audit",
        `DELETE FROM user_role_audit WHERE tenant_id = $1`,
        [tenantId],
      );

      const memberRows = await ds.query<Array<{ user_id: string }>>(
        `DELETE FROM user_tenants
         WHERE tenant_id = $1 AND user_id <> $2
         RETURNING user_id`,
        [tenantId, DENALI_OWNER_USER_ID],
      );
      deleted.user_tenants = memberRows.length;
      emitScriptInfo(`  user_tenants (non-owner): ${deleted.user_tenants}`);

      const orphanUsers = await ds.query<Array<{ id: string }>>(
        `DELETE FROM users u
         WHERE u.id = ANY($1::uuid[])
           AND u.id <> $2
           AND u.deleted_at IS NULL
           AND NOT EXISTS (
             SELECT 1 FROM user_tenants ut
             WHERE ut.user_id = u.id AND ut.deleted_at IS NULL
           )
         RETURNING u.id`,
        [memberRows.map((r) => r.user_id), DENALI_OWNER_USER_ID],
      );
      deleted.users_orphaned = orphanUsers.length;
      emitScriptInfo(`  users (orphaned, removed from denali only): ${deleted.users_orphaned}`);

      await ds.query("COMMIT");
    } catch (error) {
      await ds.query("ROLLBACK");
      throw error;
    }

    emitScriptInfo("=== Denali reset complete (owner preserved) ===");

    summary = {
      tenantId,
      subdomain: DENALI_SUBDOMAIN,
      ownerUserId: DENALI_OWNER_USER_ID,
      deleted,
      reprovisioned: false,
    };
  } finally {
    if (ds.isInitialized) {
      await ds.destroy();
    }
  }

  if (!summary) {
    fail("reset-denali-workspace: internal error — summary not built");
  }

  if (options?.reprovision) {
    emitScriptInfo("=== Re-provisioning Denali (themes, presets, template, minimal catalog) ===");
    await provisionDenaliTenant();
    summary.reprovisioned = true;
  }

  emitScriptInfo(JSON.stringify(summary, null, 2));
  return summary;
}

const isDirectRun =
  typeof process.argv[1] === "string" && process.argv[1].includes("reset-denali-workspace");

if (isDirectRun) {
  resetDenaliWorkspace({ reprovision: parseReprovisionFlag() }).catch((error: unknown) => {
    process.exitCode = 1;
  });
}

import { existsSync, readFileSync } from "node:fs";
import { resolve } from "node:path";
import { DataSource } from "typeorm";
import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { emitScriptInfo } from "./script-log";

function loadEnvFile(relativeName: string): void {
  const envPath = resolve(process.cwd(), relativeName);
  if (!existsSync(envPath)) {
    return;
  }
  const content = readFileSync(envPath, "utf8");
  for (const line of content.split("\n")) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith("#")) continue;
    const eq = trimmed.indexOf("=");
    if (eq <= 0) continue;
    const key = trimmed.slice(0, eq).trim();
    const value = trimmed.slice(eq + 1).trim();
    if (!(key in process.env)) {
      process.env[key] = value;
    }
  }
}

async function run(): Promise<void> {
  loadEnvFile(".env");
  loadEnvFile(".env.test");
  const dataSource = new DataSource(createDataSourceOptionsFromEnv());
  await dataSource.initialize();
  try {
    await dataSource.runMigrations();
    emitScriptInfo("Migrations applied successfully.");
  } finally {
    await dataSource.destroy();
  }
}

run().catch((error: unknown) => {
  const message = error instanceof Error ? error.stack ?? error.message : String(error);
  process.exitCode = 1;
});

/**
 * Idempotent bulk seed: 100 distinct leader-equivalent users on the workspace where
 * `leader@test.com` has an owner/leader membership.
 *
 * Emails: leader+1@test.com … leader+100@test.com (unique rows).
 * Tenant role in DB: `owner` (product "leader" — UserRole.Owner).
 *
 * Uses raw SQL for `user_tenants` so the script runs whether or not `session_version`
 * migration has been applied yet.
 *
 * Refuses NODE_ENV=production unless ALLOW_BULK_TEST_USER_SEED=true.
 */
import * as argon2 from "argon2";
import { DataSource } from "typeorm";
import { randomUUID } from "node:crypto";
import { createDataSourceOptionsFromEnv } from "../database/database.config";
import { emitScriptInfo } from "./script-log";
import { TenantEntity } from "../modules/identity/entities/tenant.entity";
import { UserEntity } from "../modules/identity/entities/user.entity";
import { UserTenantEntity } from "../modules/identity/entities/user-tenant.entity";
import { tryParseWorkspaceUserRole, UserRole } from "../common/auth/user-role.enum";

const ANCHOR_LEADER_EMAIL = "leader@test.com";
const TEST_USER_COUNT = 100;
const TEST_PASSWORD = "Test123456!";
const EMAIL_LOCAL_DOMAIN = "test.com";

const MEMBERSHIP_ROLE = UserRole.Owner;

function bulkLeaderEmail(index1Based: number): string {
  return `leader+${index1Based}@${EMAIL_LOCAL_DOMAIN}`.toLowerCase();
}

function bulkLeaderPhone(index1Based: number): string {
  return `+1555${String(index1Based).padStart(7, "0")}`;
}

function isLeaderEquivalentRole(role: string): boolean {
  const p = tryParseWorkspaceUserRole(role);
  return p === UserRole.Owner || p === UserRole.Leader;
}

function fail(message: string): never {
  throw new Error(message);
}

async function hasSessionVersionColumn(ds: DataSource): Promise<boolean> {
  const rows = await ds.query<{ exists: boolean }[]>(
    `SELECT EXISTS (
       SELECT 1 FROM information_schema.columns
       WHERE table_schema = 'public'
         AND table_name = 'user_tenants'
         AND column_name = 'session_version'
     ) AS exists`
  );
  return Boolean(rows[0]?.exists);
}

async function run(): Promise<void> {
  if (process.env.NODE_ENV === "production" && process.env.ALLOW_BULK_TEST_USER_SEED !== "true") {
    fail(
      "seed-bulk-test-users: refusing to run with NODE_ENV=production. " +
        "Use a non-production database or set ALLOW_BULK_TEST_USER_SEED=true after explicit review."
    );
  }

  const dataSource = new DataSource({
    ...createDataSourceOptionsFromEnv(),
    entities: [TenantEntity, UserEntity, UserTenantEntity]
  });

  await dataSource.initialize();
  const userRepo = dataSource.getRepository(UserEntity);
  const hasSv = await hasSessionVersionColumn(dataSource);

  let targetTenantId = "";
  let tenantName = "";
  let usersCreated = 0;
  let usersReused = 0;
  let membershipsCreated = 0;
  let membershipsAlready = 0;
  let membershipsRoleUpdated = 0;

  try {
    const anchorUser = await userRepo
      .createQueryBuilder("u")
      .where("LOWER(TRIM(u.email)) = LOWER(TRIM(:email))", { email: ANCHOR_LEADER_EMAIL })
      .andWhere("u.deleted_at IS NULL")
      .getOne();
    if (!anchorUser) {
      fail(
        `seed-bulk-test-users: no active user found with email "${ANCHOR_LEADER_EMAIL}". ` +
          "Run `pnpm seed` (or equivalent) first."
      );
    }

    const anchorRows = await dataSource.query<
      Array<{ tenant_id: string; role: string; name: string | null; tdel: Date | null }>
    >(
      `SELECT ut.tenant_id::text AS tenant_id, ut.role::text AS role, t.name, t.deleted_at AS tdel
       FROM user_tenants ut
       INNER JOIN tenants t ON t.id = ut.tenant_id
       WHERE ut.user_id = $1::uuid
         AND ut.deleted_at IS NULL
       ORDER BY ut.created_at ASC`,
      [anchorUser.id]
    );

    const pick = anchorRows.find(
      (r) => r.tdel == null && isLeaderEquivalentRole(r.role)
    );
    if (!pick) {
      fail(
        `seed-bulk-test-users: "${ANCHOR_LEADER_EMAIL}" has no active owner/leader membership ` +
          "in a non-deleted tenant."
      );
    }

    targetTenantId = pick.tenant_id;
    tenantName = pick.name ?? "(unknown)";

    emitScriptInfo(`Target workspace tenant_id=${targetTenantId} name=${tenantName}`);
    emitScriptInfo(
      `Seeding ${TEST_USER_COUNT} users as role=${MEMBERSHIP_ROLE} (leader-equivalent); session_version column: ${hasSv}`
    );

    const hashedPassword = await argon2.hash(TEST_PASSWORD);

    for (let i = 1; i <= TEST_USER_COUNT; i += 1) {
      const email = bulkLeaderEmail(i);
      const phone = bulkLeaderPhone(i);
      const fullName = `Leader Test ${i}`;

      let user = await userRepo
        .createQueryBuilder("u")
        .where("LOWER(TRIM(u.email)) = LOWER(TRIM(:email))", { email })
        .andWhere("u.deleted_at IS NULL")
        .getOne();
      if (!user) {
        user = await userRepo.save(
          userRepo.create({
            email,
            phone,
            hashedPassword,
            fullName,
            isEmailVerified: true,
            isPhoneVerified: true,
            telegramUserId: null
          })
        );
        usersCreated += 1;
      } else {
        usersReused += 1;
        await userRepo.update(
          { id: user.id },
          {
            phone,
            fullName,
            hashedPassword,
            isEmailVerified: true,
            isPhoneVerified: true
          }
        );
      }

      const mRows = await dataSource.query<Array<{ id: string; role: string }>>(
        `SELECT id::text AS id, role::text AS role FROM user_tenants
         WHERE user_id = $1::uuid AND tenant_id = $2::uuid AND deleted_at IS NULL
         LIMIT 1`,
        [user.id, targetTenantId]
      );
      const existing = mRows[0];

      if (existing) {
        if (existing.role !== MEMBERSHIP_ROLE) {
          if (hasSv) {
            await dataSource.query(
              `UPDATE user_tenants SET role = $1, session_version = session_version + 1, updated_at = now()
               WHERE id = $2::uuid AND deleted_at IS NULL`,
              [MEMBERSHIP_ROLE, existing.id]
            );
          } else {
            await dataSource.query(
              `UPDATE user_tenants SET role = $1, updated_at = now()
               WHERE id = $2::uuid AND deleted_at IS NULL`,
              [MEMBERSHIP_ROLE, existing.id]
            );
          }
          membershipsRoleUpdated += 1;
        } else {
          membershipsAlready += 1;
        }
      } else {
        const newId = randomUUID();
        if (hasSv) {
          await dataSource.query(
            `INSERT INTO user_tenants (id, tenant_id, created_at, updated_at, deleted_at, user_id, role, session_version)
             VALUES ($1::uuid, $2::uuid, now(), now(), NULL, $3::uuid, $4, 1)`,
            [newId, targetTenantId, user.id, MEMBERSHIP_ROLE]
          );
        } else {
          await dataSource.query(
            `INSERT INTO user_tenants (id, tenant_id, created_at, updated_at, deleted_at, user_id, role)
             VALUES ($1::uuid, $2::uuid, now(), now(), NULL, $3::uuid, $4)`,
            [newId, targetTenantId, user.id, MEMBERSHIP_ROLE]
          );
        }
        membershipsCreated += 1;
      }
    }

    const emailPattern = `^leader\\+[0-9]+@${EMAIL_LOCAL_DOMAIN.replace(".", "\\.")}$`;

    const countRows = await dataSource.query<{ c: string }[]>(
      `SELECT COUNT(*)::text AS c FROM users u
       WHERE u.deleted_at IS NULL AND u.email ~ $1`,
      [emailPattern]
    );
    const bulkEmailCount = Number(countRows[0]?.c ?? "0");

    const memberRows = await dataSource.query<{ c: string }[]>(
      `SELECT COUNT(*)::text AS c
       FROM user_tenants ut
       INNER JOIN users u ON u.id = ut.user_id AND u.deleted_at IS NULL
       WHERE ut.tenant_id = $1::uuid
         AND ut.deleted_at IS NULL
         AND ut.role = $2
         AND u.email ~ $3`,
      [targetTenantId, MEMBERSHIP_ROLE, emailPattern]
    );
    const bulkOwnerMembershipCount = Number(memberRows[0]?.c ?? "0");

    emitScriptInfo("");
    emitScriptInfo("=== seed-bulk-test-users summary ===");
    emitScriptInfo(`target_workspace_tenant_id: ${targetTenantId}`);
    emitScriptInfo(`target_workspace_name: ${tenantName}`);
    emitScriptInfo(`users_created: ${usersCreated}`);
    emitScriptInfo(`users_reused: ${usersReused}`);
    emitScriptInfo(`memberships_created: ${membershipsCreated}`);
    emitScriptInfo(`memberships_already_existing: ${membershipsAlready}`);
    emitScriptInfo(`memberships_role_corrected: ${membershipsRoleUpdated}`);
    emitScriptInfo(`db_verification_users_leader_plus_pattern: ${bulkEmailCount}`);
    emitScriptInfo(
      `db_verification_owner_memberships_leader_plus_in_target_tenant: ${bulkOwnerMembershipCount}`
    );
    emitScriptInfo(`shared_test_password: ${TEST_PASSWORD}`);
    emitScriptInfo("sample_emails:");
    emitScriptInfo(`  ${bulkLeaderEmail(1)}`);
    emitScriptInfo(`  ${bulkLeaderEmail(2)}`);
    emitScriptInfo(`  ${bulkLeaderEmail(50)}`);
    emitScriptInfo(`  ${bulkLeaderEmail(100)}`);
    emitScriptInfo("=== done ===");

    if (bulkEmailCount < TEST_USER_COUNT || bulkOwnerMembershipCount < TEST_USER_COUNT) {
      fail(
        `seed-bulk-test-users: post-seed verification expected ${TEST_USER_COUNT} users and memberships; ` +
          `got users=${bulkEmailCount}, memberships=${bulkOwnerMembershipCount}`
      );
    }
  } finally {
    await dataSource.destroy();
  }
}

run().catch((error: unknown) => {
  const message = error instanceof Error ? error.stack ?? error.message : String(error);
  if (!process.exitCode) {
    process.exitCode = 1;
  }
});

