"use client";

import { Component, type ErrorInfo, type HTMLAttributes, type ReactNode, Suspense, useEffect } from "react";

import { Alert } from "../Alert/Alert";

import { cn } from "../../utils/cn";

import styles from "./PageShell.module.css";

export type PageShellProps = Omit<HTMLAttributes<HTMLDivElement>, "children"> & {
  children: ReactNode;
  /** When set, updates `document.title` for quick parity with route metadata */
  documentTitle?: string;
  loadingFallback?: ReactNode;
};

class LayoutSectionErrorBoundary extends Component<{ children: ReactNode }, { error: Error | null }> {
  state = { error: null as Error | null };

  static getDerivedStateFromError(error: Error) {
    return { error };
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
  }

  render() {
    if (this.state.error) {
      return (
        <Alert variant="error" title="Something went wrong" role="alert">
          {this.state.error.message || "An unexpected error occurred in this section."}
        </Alert>
      );
    }
    return this.props.children;
  }
}

export function PageShell({
  children,
  className,
  documentTitle,
  loadingFallback,
  ...rest
}: PageShellProps) {
  useEffect(() => {
    if (!documentTitle) return;
    document.title = `${documentTitle} | TourOps`;
  }, [documentTitle]);

  return (
    <div className={cn(styles.root, className)} {...rest}>
      <div className={styles.inner}>
        <Suspense
          fallback={
            loadingFallback ?? (
              <p className={styles.fallback} role="status" aria-live="polite">
                Loading…
              </p>
            )
          }
        >
          <LayoutSectionErrorBoundary>{children}</LayoutSectionErrorBoundary>
        </Suspense>
      </div>
    </div>
  );
}

#!/usr/bin/env node
/**
 * Phase 9 — capability registry audit (prompt.md).
 *
 * - Every registered capability has documented CASL or query-layer wiring
 * - Product aliases resolve to registered implementation capabilities
 * - No duplicate / orphan alias targets
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");

const failures = [];
const warnings = [];

function fail(message) {
  failures.push(message);
}

function warn(message) {
  warnings.push(message);
}

function readRepo(relPath) {
  const abs = path.join(REPO_ROOT, relPath);
  if (!fs.existsSync(abs)) {
    fail(`missing file: ${relPath}`);
    return "";
  }
  return fs.readFileSync(abs, "utf8");
}

/** Capabilities enforced outside CASL `apply*FromSet` (query / route policy only). */
const QUERY_OR_POLICY_ONLY_CAPABILITIES = new Set(["tour.regional.manage"]);

function extractConstStringArray(source, constName) {
  const re = new RegExp(
    `export const ${constName}\\s*=\\s*\\[([\\s\\S]*?)\\]\\s*as const`,
    "m",
  );
  const match = source.match(re);
  if (!match) {
    return [];
  }
  const values = [];
  const inner = match[1];
  const capRe = /"([a-zA-Z][a-zA-Z0-9_.]+)"/g;
  let capMatch;
  while ((capMatch = capRe.exec(inner)) !== null) {
    values.push(capMatch[1]);
  }
  return values;
}

function extractWorkspaceCapabilityValues(registrySource) {
  const start = registrySource.indexOf("WORKSPACE_CAPABILITY_VALUES");
  if (start < 0) {
    return [];
  }
  const slice = registrySource.slice(start, start + 2000);
  const values = [];
  const re = /"([^"]+)"/g;
  let match;
  while ((match = re.exec(slice)) !== null) {
    if (match[1].includes(".")) {
      values.push(match[1]);
    }
  }
  return [...new Set(values)];
}

function extractCaslCapabilityChecks(abilityFactorySource) {
  const checks = new Set();
  const re = /caps\.has\("([^"]+)"\)/g;
  let match;
  while ((match = re.exec(abilityFactorySource)) !== null) {
    checks.add(match[1]);
  }
  return checks;
}

function extractProductAliases(registrySource) {
  const start = registrySource.indexOf("PRODUCT_CAPABILITY_ALIASES");
  if (start < 0) {
    return new Map();
  }
  const slice = registrySource.slice(start, start + 2000);
  const aliases = new Map();
  const re = /"([^"]+)":\s*"([^"]+)"/g;
  let match;
  while ((match = re.exec(slice)) !== null) {
    aliases.set(match[1], match[2]);
  }
  return aliases;
}

function extractMarketingLabelAliases(registrySource) {
  const start = registrySource.indexOf("MARKETING_LABEL_CAPABILITY_ALIASES");
  if (start < 0) {
    return new Map();
  }
  const slice = registrySource.slice(start, start + 1500);
  const aliases = new Map();
  const re = /(\w+):\s*"([^"]+)"/g;
  let match;
  while ((match = re.exec(slice)) !== null) {
    aliases.set(match[1], match[2]);
  }
  return aliases;
}

const capabilitiesSrc = readRepo("packages/shared/rbac/capabilities.ts");
const registrySrc = readRepo("packages/shared/rbac/capability-registry.ts");
const abilitySrc = readRepo("packages/shared/rbac/ability.factory.ts");

const registered = new Set(extractWorkspaceCapabilityValues(registrySrc));
const caslWired = extractCaslCapabilityChecks(abilitySrc);
const productAliases = extractProductAliases(registrySrc);
const marketingAliases = extractMarketingLabelAliases(registrySrc);

for (const cap of registered) {
  if (QUERY_OR_POLICY_ONLY_CAPABILITIES.has(cap)) {
    continue;
  }
  if (!caslWired.has(cap)) {
    fail(`[casl-wiring] registered capability "${cap}" has no caps.has() grant in ability.factory.ts`);
  }
}

for (const [alias, target] of productAliases) {
  if (!registered.has(target)) {
    fail(`[alias] PRODUCT_CAPABILITY_ALIASES.${alias} → "${target}" is not in WORKSPACE_CAPABILITY_VALUES`);
  }
}

for (const [, target] of marketingAliases) {
  if (!registered.has(target)) {
    fail(`[alias] MARKETING_LABEL alias target "${target}" is not registered`);
  }
}

const tourCaps = new Set(extractConstStringArray(capabilitiesSrc, "TOUR_CAPABILITIES"));
const settingsCaps = new Set(extractConstStringArray(capabilitiesSrc, "SETTINGS_CAPABILITIES"));
const moduleCaps = new Set(extractConstStringArray(capabilitiesSrc, "MODULE_CAPABILITIES"));
const marketingCaps = new Set(extractConstStringArray(capabilitiesSrc, "MARKETING_CAPABILITIES"));

for (const cap of registered) {
  const inFamily =
    tourCaps.has(cap) ||
    settingsCaps.has(cap) ||
    moduleCaps.has(cap) ||
    marketingCaps.has(cap);
  if (!inFamily) {
    fail(`[registry] "${cap}" in WORKSPACE_CAPABILITY_VALUES but missing from TOUR/SETTINGS/MODULE/MARKETING const arrays`);
  }
}

for (const cap of tourCaps) {
  if (!registered.has(cap)) {
    warn(`[registry] TOUR_CAPABILITIES includes "${cap}" but not WORKSPACE_CAPABILITY_VALUES`);
  }
}

const policySrc = readRepo("apps/api/src/modules/tours/utils/tour-patch-field-policy.ts");
const policyCaps = new Set();
const capRe = /requiredCapability:\s*"([^"]+)"/g;
let policyMatch;
while ((policyMatch = capRe.exec(policySrc)) !== null) {
  policyCaps.add(policyMatch[1]);
}

for (const cap of policyCaps) {
  if (!registered.has(cap)) {
    fail(`[patch-policy] requiredCapability "${cap}" is not a registered workspace capability`);
  }
}

if (failures.length > 0) {
  for (const line of failures) {
  }
  process.exit(1);
}

if (warnings.length > 0) {
  for (const line of warnings) {
  }
}

#!/usr/bin/env node
/**
 * Optional p95 probe for tour list path (Phase 7.4 — local/staging only).
 * Requires API :3001 and optional web :3000 with ws1-rbac host.
 */
import { performance } from "node:perf_hooks";
import { spawnSync } from "node:child_process";

const SAMPLES = Number(process.env.BENCH_TOUR_SAMPLES ?? "12");
const WARN_P95_MS = Number(process.env.BENCH_TOUR_P95_WARN_MS ?? "800");
const HOST = process.env.BENCH_TOUR_HOST ?? "ws1-rbac.localhost:3001";
const PATH = process.env.BENCH_TOUR_PATH ?? "/api/v2/tours";

function curlMs(args) {
  const t0 = performance.now();
  const r = spawnSync("curl", args, { encoding: "utf8" });
  return { ms: performance.now() - t0, ok: r.status === 0, status: r.status };
}

const health = curlMs(["-sf", "http://127.0.0.1:3001/health"]);
if (!health.ok) {
  process.exit(0);
}

const samples = [];
for (let i = 0; i < SAMPLES; i += 1) {
  const { ms, ok, status } = curlMs([
    "-sf",
    "-o",
    "/dev/null",
    "-w",
    "%{http_code}",
    `http://127.0.0.1:3001${PATH}`,
    "-H",
    `Host: ${HOST}`,
  ]);
  if (!ok) {
    process.exit(0);
  }
  samples.push(ms);
}

samples.sort((a, b) => a - b);
const p95 = samples[Math.min(samples.length - 1, Math.floor(samples.length * 0.95))];
const p50 = samples[Math.floor(samples.length * 0.5)];

if (p95 > WARN_P95_MS) {
  process.exit(1);
}

#!/usr/bin/env node
/**
 * Phase 17.1 — fail CI when capability governance registry drifts.
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");

const failures = [];

function fail(msg) {
  failures.push(msg);
}

function readRepo(rel) {
  return fs.readFileSync(path.join(REPO_ROOT, rel), "utf8");
}

function extractWorkspaceCapabilities(registrySrc) {
  const start = registrySrc.indexOf("WORKSPACE_CAPABILITY_VALUES");
  const slice = registrySrc.slice(start, start + 2500);
  const values = [];
  const re = /"([^"]+\.[^"]+)"/g;
  let m;
  while ((m = re.exec(slice)) !== null) {
    values.push(m[1]);
  }
  return [...new Set(values)];
}

function extractGovernedKeys(governanceSrc) {
  const keys = [];
  const re = /key:\s*"([^"]+)"/g;
  let m;
  while ((m = re.exec(governanceSrc)) !== null) {
    keys.push(m[1]);
  }
  return keys;
}

function extractOwners(governanceSrc) {
  const owners = [];
  const re = /owner:\s*"([^"]+)"/g;
  let m;
  while ((m = re.exec(governanceSrc)) !== null) {
    owners.push(m[1]);
  }
  return owners;
}

const registrySrc = readRepo("packages/shared/rbac/capability-registry.ts");
const governanceSrc = readRepo("packages/shared/rbac/capability-governance.ts");

const registered = extractWorkspaceCapabilities(registrySrc);
const governed = extractGovernedKeys(governanceSrc);
const governedSet = new Set(governed);

for (const cap of registered) {
  if (!governedSet.has(cap)) {
    fail(`undocumented capability: ${cap}`);
  }
}

for (const cap of governed) {
  if (!registered.includes(cap)) {
    fail(`unknown governed capability: ${cap}`);
  }
}

const dupes = governed.filter((k, i) => governed.indexOf(k) !== i);
if (dupes.length) {
  fail(`duplicate governance keys: ${[...new Set(dupes)].join(", ")}`);
}

const owners = extractOwners(governanceSrc);
if (owners.some((o) => !o.trim())) {
  fail("capability missing owner");
}

if (failures.length) {
  for (const f of failures) {
  }
  process.exit(1);
}

