#!/usr/bin/env node
/**
 * Tenant isolation architecture guardrails for CI.
 *
 * Checks:
 * 1) dataSource.query / this.dataSource.query in runtime API code (allowlisted paths only).
 * 1b) Allowlisted dataSource.query: first-arg SQL must be catalog/health-shaped or contain tenant binding.
 * 2) @Body() DTO classes that declare tenant_id or tenantId (client-controlled tenant) unless response-shaped / allowlisted.
 * 3) Active runtime SECURITY DEFINER usage must be documented in docs/security/security-definer.md.
 * 4) Explicit HTTP body tenant reads (req.request.body.tenantId / tenant_id, including bracket access).
 * 5) EntityManager raw SQL: manager.query( — first static SQL arg must include tenant_id/workspace_id or GUC set_config.
 * 6) createQueryBuilder: chain window must reference tenant/workspace scoping, or `// tenant-isolation:qb-exempt` above.
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");
const ALLOWLIST_PATH = path.join(__dirname, "tenant-isolation-guardrails.allowlist.json");

function readAllowlist() {
  const raw = fs.readFileSync(ALLOWLIST_PATH, "utf8");
  return JSON.parse(raw);
}

function walk(dir, acc = []) {
  if (!fs.existsSync(dir)) return acc;
  for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
    const p = path.join(dir, ent.name);
    if (ent.isDirectory()) {
      if (ent.name === "node_modules" || ent.name === "dist") continue;
      walk(p, acc);
    } else if (ent.isFile() && ent.name.endsWith(".ts")) {
      acc.push(p);
    }
  }
  return acc;
}

function normPosix(p) {
  return p.split(path.sep).join("/");
}

function isIgnoredPath(rel, ignored) {
  return ignored.some((prefix) => rel.startsWith(prefix.replace(/^\.\//, "")));
}

function lineNumberAt(src, idx) {
  return src.slice(0, idx).split("\n").length;
}

/** --- Check 1: dataSource.query --- */
function checkDataSourceQuery(allow) {
  const apiRoot = path.join(REPO_ROOT, "apps/api/src");
  const files = walk(apiRoot).map((p) => ({
    abs: p,
    rel: normPosix(path.relative(REPO_ROOT, p))
  }));

  const ignored = allow.ignoredPathsForDataSourceQuery.map((x) =>
    normPosix(x.replace(/^\.\//, ""))
  );
  const allowedFiles = new Set(allow.dataSourceQueryPaths.map(normPosix));

  const violations = [];
  const re = /\b(?:this\.)?dataSource\.query\s*\(/g;

  for (const { abs, rel } of files) {
    if (isIgnoredPath(rel, ignored)) continue;
    const text = fs.readFileSync(abs, "utf8");
    if (!re.test(text)) continue;
    re.lastIndex = 0;
    if (!allowedFiles.has(rel)) {
      violations.push(
        `[DATASOURCE_QUERY] ${rel}: uses dataSource.query — use repositories / QueryBuilder under RLS tenant binding, or add path to scripts/tenant-isolation-guardrails.allowlist.json with justification.`
      );
    }
  }
  return violations;
}

/** --- Check 1b: allowlisted dataSource.query SQL body --- */
function skipWs(s, i) {
  let j = i;
  while (j < s.length && /\s/.test(s[j])) j++;
  return j;
}

function extractFirstStringOrTemplateArg(src, openParenIdx) {
  let i = skipWs(src, openParenIdx + 1);
  if (i >= src.length) return null;
  const c = src[i];
  if (c === "`") {
    let j = i + 1;
    while (j < src.length && src[j] !== "`") j += 1;
    if (j >= src.length) return null;
    return src.slice(i + 1, j);
  }
  if (c === '"' || c === "'") {
    const quote = c;
    let j = i + 1;
    let esc = false;
    while (j < src.length) {
      if (esc) {
        esc = false;
        j += 1;
        continue;
      }
      if (src[j] === "\\") {
        esc = true;
        j += 1;
        continue;
      }
      if (src[j] === quote) {
        return src.slice(i + 1, j);
      }
      j += 1;
    }
    return null;
  }
  return null;
}

function sqlLooksSafeCatalogOrHealth(sql) {
  if (!sql || typeof sql !== "string") return false;
  const s = sql.replace(/\/\*[\s\S]*?\*\//g, " ").trim();
  if (/^\s*select\s+1\b/i.test(s)) return true;
  if (/\binformation_schema\b/i.test(s)) return true;
  if (/\bpg_catalog\b/i.test(s)) return true;
  if (/^\s*(begin|commit|rollback)\b/i.test(s)) return true;
  return false;
}

function sqlShowsTenantBinding(sql) {
  if (!sql || typeof sql !== "string") return false;
  return (
    /\btenant_id\b/i.test(sql) ||
    /\bworkspace_id\b/i.test(sql) ||
    /set_config\s*\(\s*['"]app\.tenant_id['"]/i.test(sql) ||
    /current_setting\s*\(\s*['"]app\.tenant_id['"]/i.test(sql)
  );
}

function checkAllowlistedDataSourceQuerySql(allow) {
  const violations = [];
  const allowedRel = (allow.dataSourceQueryPaths || []).map(normPosix);
  const re = /\b(?:this\.)?dataSource\.query\s*\(/g;

  for (const rel of allowedRel) {
    const abs = path.join(REPO_ROOT, rel);
    if (!fs.existsSync(abs)) continue;
    const text = fs.readFileSync(abs, "utf8");
    let m;
    while ((m = re.exec(text)) !== null) {
      const openParen = m.index + m[0].length - 1;
      const sql = extractFirstStringOrTemplateArg(text, openParen);
      if (sql === null) {
        violations.push(
          `[RAW_SQL_TENANT] ${rel}:${lineNumberAt(text, m.index)}: dataSource.query uses non-literal SQL — add a static template/string so tenant binding can be verified, or refactor.`
        );
        continue;
      }
      if (sqlLooksSafeCatalogOrHealth(sql) || sqlShowsTenantBinding(sql)) {
        continue;
      }
      violations.push(
        `[RAW_SQL_TENANT] ${rel}:${lineNumberAt(text, m.index)}: allowlisted dataSource.query SQL lacks tenant_id/workspace_id/app.tenant_id binding and is not a catalog/health probe.`
      );
    }
  }
  return violations;
}

/** --- Check 2: Body + tenant scope fields --- */
function stripTsComments(src) {
  return src
    .replace(/\/\*[\s\S]*?\*\//g, " ")
    .replace(/\/\/[^\n]*/g, " ");
}

function iterExportClassBodies(ts) {
  const out = [];
  const re = /^export\s+class\s+(\w+)(?:\s+extends\s+[\w.<>,\s]+)?\s*\{/gm;
  let m;
  while ((m = re.exec(ts)) !== null) {
    const name = m[1];
    const openBraceIdx = m.index + m[0].length - 1;
    let depth = 0;
    for (let i = openBraceIdx; i < ts.length; i++) {
      const ch = ts[i];
      if (ch === "{") depth++;
      else if (ch === "}") {
        depth--;
        if (depth === 0) {
          out.push({ name, body: ts.slice(openBraceIdx + 1, i) });
          break;
        }
      }
    }
  }
  return out;
}

function classBodyDeclaresClientTenantScope(body) {
  const c = stripTsComments(body);
  if (/\btenant_id\b/.test(c)) return true;
  if (/\btenantId\s*[!?]?\s*:/.test(c)) return true;
  return false;
}

function extractExportedClassesWithClientTenantScope(dtoText) {
  return iterExportClassBodies(dtoText).filter((x) => classBodyDeclaresClientTenantScope(x.body));
}

function isResponseLikeClassName(name, suffixes) {
  return suffixes.some((s) => name.endsWith(s));
}

function checkBodyTenantDto(allow) {
  const modulesRoot = path.join(REPO_ROOT, "apps/api/src/modules");
  const dtoFiles = walk(modulesRoot).filter((p) => p.includes(`${path.sep}dto${path.sep}`));

  const allowBody = new Set(allow.bodyDtoAllowlist);
  const suffixes = allow.dtoResponseNameSuffixes;

  const riskyDtoNames = new Map();
  for (const abs of dtoFiles) {
    const text = fs.readFileSync(abs, "utf8");
    for (const { name } of extractExportedClassesWithClientTenantScope(text)) {
      if (allowBody.has(name)) continue;
      if (isResponseLikeClassName(name, suffixes)) continue;
      riskyDtoNames.set(name, normPosix(path.relative(REPO_ROOT, abs)));
    }
  }

  const controllerFiles = walk(modulesRoot).filter((p) => p.endsWith("controller.ts"));
  const bodyTypeRe = /@Body(?:\([^)]*\))?\s+\w+\s*:\s*(\w+)/g;
  const violations = [];

  for (const abs of controllerFiles) {
    const text = fs.readFileSync(abs, "utf8");
    let m;
    while ((m = bodyTypeRe.exec(text)) !== null) {
      const typeName = m[1];
      if (riskyDtoNames.has(typeName)) {
        violations.push(
          `[BODY_DTO_TENANT] ${normPosix(path.relative(REPO_ROOT, abs))}: @Body() uses ${typeName} — declares tenant_id and/or tenantId (${riskyDtoNames.get(typeName)}). Tenant scope must come from Host/JWT/RLS, not client body (allowlist only with security review).`
        );
      }
    }
  }
  return violations;
}

/** --- Check: req / request body tenant --- */
function checkHttpBodyTenantAccess(allow) {
  const roots = [
    path.join(REPO_ROOT, "apps/api/src/modules"),
    path.join(REPO_ROOT, "apps/api/src/common"),
    path.join(REPO_ROOT, "apps/api/src/jobs")
  ];
  const ignored = (allow.ignoredPathsForHttpBodyTenant || [
    "apps/api/src/database/migrations/",
    "apps/api/src/scripts/",
    "apps/api/test/",
    "apps/api/dist/"
  ]).map((x) => normPosix(x.replace(/^\.\//, "")));

  const patterns = [
    { id: "HTTP_BODY.tenantId", re: /\b(?:req|request)\s*\.\s*body\s*\.\s*tenantId\b/g },
    { id: "HTTP_BODY.tenant_id", re: /\b(?:req|request)\s*\.\s*body\s*\.\s*tenant_id\b/g },
    {
      id: "HTTP_BODY['tenantId']",
      re: /\b(?:req|request)\s*\.\s*body\s*\[\s*["']tenantId["']\s*\]/g
    },
    {
      id: "HTTP_BODY['tenant_id']",
      re: /\b(?:req|request)\s*\.\s*body\s*\[\s*["']tenant_id["']\s*\]/g
    }
  ];

  const violations = [];
  for (const root of roots) {
    for (const abs of walk(root)) {
      const rel = normPosix(path.relative(REPO_ROOT, abs));
      if (isIgnoredPath(rel, ignored)) continue;
      const text = fs.readFileSync(abs, "utf8");
      for (const { id, re } of patterns) {
        re.lastIndex = 0;
        let m;
        while ((m = re.exec(text)) !== null) {
          violations.push(
            `[${id}] ${rel}:${lineNumberAt(text, m.index)}: do not read tenant scope from the HTTP body — use Host/JWT + RLS.`
          );
        }
      }
    }
  }
  return violations;
}

/** --- Check: manager.query raw SQL --- */
function checkManagerQueryTenant(allow) {
  const apiRoot = path.join(REPO_ROOT, "apps/api/src");
  const ignored = (allow.ignoredPathsForManagerQuery || [
    "apps/api/src/database/migrations/",
    "apps/api/src/scripts/",
    "apps/api/test/",
    "apps/api/dist/",
    "apps/api/src/database/tenant-db-context.service.ts"
  ]).map((x) => normPosix(x.replace(/^\.\//, "")));

  const violations = [];
  const re = /\bmanager\.query\s*\(/g;

  for (const abs of walk(apiRoot)) {
    const rel = normPosix(path.relative(REPO_ROOT, abs));
    if (isIgnoredPath(rel, ignored)) continue;
    const text = fs.readFileSync(abs, "utf8");
    let m;
    while ((m = re.exec(text)) !== null) {
      const openParen = m.index + m[0].length - 1;
      const sql = extractFirstStringOrTemplateArg(text, openParen);
      if (sql === null) {
        violations.push(
          `[MANAGER_RAW_SQL] ${rel}:${lineNumberAt(text, m.index)}: manager.query uses non-literal SQL — cannot verify tenant binding.`
        );
        continue;
      }
      if (sqlLooksSafeCatalogOrHealth(sql) || sqlShowsTenantBinding(sql)) {
        continue;
      }
      violations.push(
        `[MANAGER_RAW_SQL] ${rel}:${lineNumberAt(text, m.index)}: manager.query SQL lacks tenant_id/workspace_id/app.tenant_id binding (defense-in-depth for raw SQL).`
      );
    }
  }
  return violations;
}

const QB_TENANT_MARKERS =
  /\btenant_id\b|\btenantId\b|:tenantId|\bworkspace_id\b|\bworkspaceId\b|:workspaceId|\.tenant_id\b|\.tenantId\b/;

function queryBuilderMarkedExempt(src, qbIdx) {
  const head = src.slice(0, qbIdx);
  const lines = head.split("\n").slice(-8);
  return lines.some((ln) => ln.includes("tenant-isolation:qb-exempt"));
}

function sliceTypeormQbChain(src, qbIdx) {
  const tail = src.slice(qbIdx);
  const patterns = [
    /\.getMany\s*\(/,
    /\.getOne\s*\(/,
    /\.execute\s*\(/,
    /\.getCount\s*\(/,
    /\.getRawMany\s*[\(<]/,
    /\.getRawOne\s*[\(<]/
  ];
  let end = tail.length;
  for (const re of patterns) {
    re.lastIndex = 0;
    const m = re.exec(tail);
    if (m) {
      end = Math.min(end, m.index + m[0].length);
    }
  }
  return tail.slice(0, end);
}

function checkCreateQueryBuilderTenant(allow) {
  const apiRoot = path.join(REPO_ROOT, "apps/api/src");
  const ignored = (allow.ignoredPathsForQueryBuilderTenant || []).map((x) =>
    normPosix(x.replace(/^\.\//, ""))
  );
  const violations = [];
  const re = /\.createQueryBuilder\s*\(/g;

  for (const abs of walk(apiRoot)) {
    const rel = normPosix(path.relative(REPO_ROOT, abs));
    if (isIgnoredPath(rel, ignored)) continue;
    const text = fs.readFileSync(abs, "utf8");
    let m;
    while ((m = re.exec(text)) !== null) {
      if (queryBuilderMarkedExempt(text, m.index)) continue;
      const chain = sliceTypeormQbChain(text, m.index);
      if (!QB_TENANT_MARKERS.test(chain)) {
        violations.push(
          `[QUERY_BUILDER_TENANT] ${rel}:${lineNumberAt(text, m.index)}: TypeORM QueryBuilder chain has no tenant_id / tenantId / workspace_id predicate — add an explicit tenant/workspace filter, or place // tenant-isolation:qb-exempt on the preceding line with justification.`
        );
      }
    }
  }
  return violations;
}

/** --- Check 3: Active runtime SECURITY DEFINER registry --- */
function extractSqlTemplateLiterals(tsContent) {
  const out = [];
  const re = /(?:queryRunner|dataSource)\.query\s*\(\s*`([\s\S]*?)`\s*[,)]/g;
  let m;
  while ((m = re.exec(tsContent)) !== null) {
    out.push(m[1]);
  }
  return out;
}

function extractFunctionsWithSecurityDefiner(sql) {
  if (!/\bSECURITY\s+DEFINER\b/i.test(sql)) return [];
  const names = new Set();
  const re = /CREATE\s+(?:OR\s+REPLACE\s+)?FUNCTION\s+([a-z0-9_]+)\s*\(/gi;
  let m;
  while ((m = re.exec(sql)) !== null) {
    names.add(m[1].toLowerCase());
  }
  return [...names];
}

function parseSecurityDefinerDocFunctions(docMarkdown) {
  if (/Active runtime `SECURITY DEFINER` functions:\s*none/i.test(docMarkdown)) {
    return new Set();
  }
  const names = new Set();
  const rowRe = /`public\.([a-z0-9_]+)\(/gi;
  let m;
  while ((m = rowRe.exec(docMarkdown)) !== null) {
    names.add(m[1].toLowerCase());
  }
  return names;
}

function checkSecurityDefinerRegistry() {
  const docPath = path.join(REPO_ROOT, "docs/security/security-definer.md");
  if (!fs.existsSync(docPath)) {
    return [`[SECURITY_DEFINER_DOC] Missing ${normPosix(path.relative(REPO_ROOT, docPath))}`];
  }
  const documented = parseSecurityDefinerDocFunctions(fs.readFileSync(docPath, "utf8"));
  const apiRoot = path.join(REPO_ROOT, "apps/api/src");
  const fromRuntime = new Set();
  for (const abs of walk(apiRoot)) {
    const rel = normPosix(path.relative(REPO_ROOT, abs));
    if (rel.includes("/database/migrations/")) {
      continue;
    }
    const text = fs.readFileSync(abs, "utf8");
    for (const sql of extractSqlTemplateLiterals(text)) {
      for (const fn of extractFunctionsWithSecurityDefiner(sql)) {
        fromRuntime.add(fn);
      }
    }
  }

  const violations = [];
  for (const fn of fromRuntime) {
    if (!documented.has(fn)) {
      violations.push(
        `[SECURITY_DEFINER] Active runtime SECURITY DEFINER function "${fn}" is not documented in docs/security/security-definer.md.`
      );
    }
  }

  for (const fn of documented) {
    if (!fromRuntime.has(fn)) {
      violations.push(
        `[SECURITY_DEFINER] docs/security/security-definer.md lists "${fn}" but no active runtime SECURITY DEFINER SQL was found — remove stale entry.`
      );
    }
  }

  return violations;
}

function main() {
  let allow;
  try {
    allow = readAllowlist();
  } catch (e) {
    process.exit(2);
  }

  const all = [
    ...checkDataSourceQuery(allow),
    ...checkAllowlistedDataSourceQuerySql(allow),
    ...checkBodyTenantDto(allow),
    ...checkHttpBodyTenantAccess(allow),
    ...checkManagerQueryTenant(allow),
    ...checkCreateQueryBuilderTenant(allow),
    ...checkSecurityDefinerRegistry()
  ];

  if (all.length > 0) {
    for (const v of all) {
    }
    process.exit(1);
  }
}

main();

#!/usr/bin/env node
/**
 * Tour domain architecture guardrails for CI.
 *
 * Closes the residual hole flagged in `promptq.md` Phase P2: ESLint already forbids legacy
 * `EventKind` symbols in the wizard scope, but the **API tours module** has no static linter.
 * This script greps the api `tours` source tree and fails the build if a forbidden symbol
 * appears anywhere — defensive net for refactors that re-introduce dual classification.
 *
 * Mirrors the style of `scripts/check-tenant-isolation-guardrails.mjs`.
 *
 * Checks:
 * 1) `apps/api/src/modules/tours/**` must not import or reference any legacy `EventKind`
 *    symbol (`EventKind`, `EventKindResolverInput`, `resolveEventKindFromTourContext`,
 *    `eventKindForDomainProfile`, `domainProfileFromEventKindBestEffort`).
 * 2) `apps/web/src/features/tours/wizard/**` is already lint-guarded via `.eslintrc.json`,
 *    but this script double-checks for parity (cheap belt-and-suspenders).
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");

const FORBIDDEN_SYMBOLS = [
  "EventKind",
  "EventKindResolverInput",
  "resolveEventKindFromTourContext",
  "eventKindForDomainProfile",
  "domainProfileFromEventKindBestEffort",
];

// Self-referential files: fitness specs that LIST the forbidden symbols as string literals.
// Excluding them is safe because each such file lives next to the rule it enforces and is
// covered by independent peer review when added.
const SELF_REFERENTIAL_FITNESS_FILES = new Set([
  "apps/api/src/modules/tours/fitness.spec.ts",
]);

const SCOPES = [
  {
    label: "apps/api tours module",
    root: path.join(REPO_ROOT, "apps/api/src/modules/tours"),
    extensions: [".ts"],
    ignoredFileSuffixes: [".d.ts"],
  },
  {
    label: "apps/web wizard scope",
    root: path.join(REPO_ROOT, "apps/web/src/features/tours/wizard"),
    extensions: [".ts", ".tsx"],
    ignoredFileSuffixes: [".d.ts"],
  },
];

function walk(dir, exts, acc = []) {
  if (!fs.existsSync(dir)) return acc;
  for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
    const p = path.join(dir, ent.name);
    if (ent.isDirectory()) {
      if (ent.name === "node_modules" || ent.name === "dist" || ent.name === ".next") continue;
      walk(p, exts, acc);
    } else if (ent.isFile() && exts.some((ext) => ent.name.endsWith(ext))) {
      acc.push(p);
    }
  }
  return acc;
}

function normPosix(p) {
  return p.split(path.sep).join("/");
}

// Strip line- and block- comments from TypeScript source so the symbol scan does not flag
// legitimate documentation that names the legacy symbols (e.g. recipe blocks in
// `profileRules/rules.ts`). Naive but sufficient — does not need to be lossless; we only
// care about whether a forbidden identifier appears in **code**.
function stripComments(source) {
  // Remove block comments (non-greedy).
  let out = source.replace(/\/\*[\s\S]*?\*\//g, "");
  // Remove line comments (full line or end-of-line).
  out = out.replace(/(^|[^:])\/\/.*$/gm, "$1");
  return out;
}

function scanScope({ label, root, extensions, ignoredFileSuffixes }) {
  const files = walk(root, extensions).filter(
    (p) => !ignoredFileSuffixes.some((suffix) => p.endsWith(suffix)),
  );
  const violations = [];
  for (const abs of files) {
    const rel = normPosix(path.relative(REPO_ROOT, abs));
    if (SELF_REFERENTIAL_FITNESS_FILES.has(rel)) continue;
    const text = stripComments(fs.readFileSync(abs, "utf8"));
    for (const symbol of FORBIDDEN_SYMBOLS) {
      const re = new RegExp(`\\b${symbol}\\b`);
      if (re.test(text)) {
        violations.push({ scope: label, file: rel, symbol });
      }
    }
  }
  return violations;
}

let allViolations = [];
for (const scope of SCOPES) {
  allViolations = allViolations.concat(scanScope(scope));
}

if (allViolations.length === 0) {
  process.exit(0);
}

for (const v of allViolations) {
}
process.exit(1);

#!/usr/bin/env node
/**
 * Phase 7 — tour RBAC / validation drift guardrails (prompt.md).
 *
 * Static parity checks (no DB):
 * 1. PATCH rank gates: @repo/types ↔ API tour-patch-field-policy ↔ web editCoreFieldConfig
 * 2. PATCH DTO coverage: every UpdateTourDto key appears in API policy matrix
 * 3. Write pipeline wiring on ToursController
 * 4. Submit-required wiring: API uses @repo/types getRequiredSubmitFieldPathsForProfile
 *
 * Run parity unit tests separately in CI (see architecture-guardrails tour-rbac-parity job).
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");

const failures = [];

function fail(message) {
  failures.push(message);
}

function readRepo(relPath) {
  const abs = path.join(REPO_ROOT, relPath);
  if (!fs.existsSync(abs)) {
    fail(`missing file: ${relPath}`);
    return "";
  }
  return fs.readFileSync(abs, "utf8");
}

/** Extract `{ dtoKey, minRoleForEdit }` rows from TS policy tables. */
function extractPatchRankGates(source, arrayName) {
  const gates = new Map();
  const arrayStart = source.indexOf(arrayName);
  if (arrayStart < 0) {
    return gates;
  }
  const slice = source.slice(arrayStart, arrayStart + 12_000);
  const ruleRe =
    /dtoKey:\s*["']([^"']+)["'][^{]*minRoleForEdit:\s*["']([^"']+)["']/g;
  let match;
  while ((match = ruleRe.exec(slice)) !== null) {
    gates.set(match[1], match[2]);
  }
  return gates;
}

/** Web `CORE_ROLE_OVERRIDES` leader gates → wire DTO keys. */
function extractWebCoreLeaderGates(source) {
  const gates = new Map();
  const wireByEditId = {
    "core.totalCapacity": "total_capacity",
    "core.capacity": "total_capacity",
  };
  const block = source.includes("CORE_ROLE_OVERRIDES")
    ? source.slice(source.indexOf("CORE_ROLE_OVERRIDES"))
    : source;
  const re =
    /["'](core\.(?:totalCapacity|capacity))["']:\s*\{[^}]*minRoleForEdit:\s*["']([^"']+)["']/g;
  let match;
  while ((match = re.exec(block)) !== null) {
    const wireKey = wireByEditId[match[1]];
    if (wireKey) {
      gates.set(wireKey, match[2]);
    }
  }
  return gates;
}

const TOUR_PATCH_CONTRACT_REL = "packages/shared-contracts/src/tours/tour-patch-contract.ts";

function extractApiPolicyDtoKeys(source) {
  const keys = new Set();
  const arrayStart =
    source.indexOf("TOUR_PATCH_CONTRACT_RULES") >= 0
      ? source.indexOf("TOUR_PATCH_CONTRACT_RULES")
      : source.indexOf("TOUR_PATCH_FIELD_POLICY_RULES");
  if (arrayStart < 0) {
    return keys;
  }
  const slice = source.slice(arrayStart, arrayStart + 14_000);
  const re = /dtoKey:\s*["']([^"']+)["']/g;
  let match;
  while ((match = re.exec(slice)) !== null) {
    keys.add(match[1]);
  }
  return keys;
}

function extractUpdateTourDtoKeys(source) {
  const keys = new Set();
  const classMatch = source.match(/export class UpdateTourDto\s*\{([\s\S]*?)^\}/m);
  if (!classMatch) {
    return keys;
  }
  const body = classMatch[1];
  const re = /^\s{2}([a-zA-Z][\w]*)\??:/gm;
  let match;
  while ((match = re.exec(body)) !== null) {
    keys.add(match[1]);
  }
  return keys;
}

function checkPatchRankGateParity() {
  const typesSrc = readRepo("packages/types/src/tour-patch-field-policy.ts");
  const contractSrc = readRepo(TOUR_PATCH_CONTRACT_REL);
  const webSrc = readRepo("apps/web/src/features/tours/config/editCoreFieldConfig.ts");

  const typesGates = extractPatchRankGates(typesSrc, "TOUR_PATCH_FIELD_RULES");
  const apiGates = extractPatchRankGates(contractSrc, "TOUR_PATCH_CONTRACT_RULES");
  const webGates = extractWebCoreLeaderGates(webSrc);

  for (const [dtoKey, minRole] of typesGates) {
    const apiRole = apiGates.get(dtoKey);
    if (apiRole !== minRole) {
      fail(
        `[patch-rank] @repo/types ${dtoKey} minRole=${minRole} but API has ${apiRole ?? "none"}`,
      );
    }
    const webRole = webGates.get(dtoKey);
    if (webRole !== minRole) {
      fail(
        `[patch-rank] @repo/types ${dtoKey} minRole=${minRole} but web editCore maps to ${webRole ?? "none"}`,
      );
    }
  }

  for (const [dtoKey, minRole] of apiGates) {
    if (!typesGates.has(dtoKey)) {
      fail(
        `[patch-rank] API ranks ${dtoKey}@${minRole} but @repo/types TOUR_PATCH_FIELD_RULES omits it — extend types mirror`,
      );
    }
  }
}

function checkPatchDtoCoverage() {
  const dtoSrc = readRepo("apps/api/src/modules/tours/dto/update-tour.dto.ts");
  const contractSrc = readRepo(TOUR_PATCH_CONTRACT_REL);
  const dtoKeys = extractUpdateTourDtoKeys(dtoSrc);
  const policyKeys = extractApiPolicyDtoKeys(contractSrc);

  for (const key of dtoKeys) {
    if (!policyKeys.has(key)) {
      fail(`[patch-coverage] UpdateTourDto.${key} missing from TOUR_PATCH_FIELD_POLICY_RULES`);
    }
  }

  for (const key of policyKeys) {
    if (!dtoKeys.has(key)) {
      fail(`[patch-coverage] policy dtoKey ${key} not found on UpdateTourDto`);
    }
  }
}

function checkWritePipelineWiring() {
  const controller = readRepo("apps/api/src/modules/tours/tours.controller.ts");
  if (!controller.includes("assertTourPatchWritePreMerge")) {
    fail("[pipeline] ToursController.update must call assertTourPatchWritePreMerge");
  }
  if (!controller.includes("assertTourCreateWritePreMerge")) {
    fail("[pipeline] ToursController.create must call assertTourCreateWritePreMerge");
  }
  if (controller.includes("assertTourPatchAbilities(")) {
    fail("[pipeline] use assertTourPatchWritePreMerge instead of direct assertTourPatchAbilities");
  }
}

function checkSubmitRequiredWiring() {
  const apiAssert = readRepo(
    "apps/api/src/modules/tours/utils/assert-profile-required-fields-for-submit.ts",
  );
  if (!apiAssert.includes("getRequiredSubmitFieldPathsForProfile")) {
    fail("[submit-required] API assert must import getRequiredSubmitFieldPathsForProfile from @repo/types");
  }
  if (!apiAssert.includes("@repo/types")) {
    fail("[submit-required] API assert must depend on @repo/types");
  }

  const typesSrc = readRepo("packages/types/src/tour-profile-submit-required.ts");
  if (!typesSrc.includes("WIZARD_SUBMIT_REQUIRED_FIELD_PATHS")) {
    fail("[submit-required] missing WIZARD_SUBMIT_REQUIRED_FIELD_PATHS in @repo/types");
  }

  const publishTransition = readRepo(
    "apps/api/src/modules/tours/policies/assert-tour-publish-transition.ts",
  );
  if (!publishTransition.includes("assertProfileRequiredFieldsForPublish")) {
    fail("[submit-required] assert-tour-publish-transition must call assertProfileRequiredFieldsForPublish");
  }

  const service = readRepo("apps/api/src/modules/tours/tours.service.ts");
  if (service.includes("assertProfileRequiredFieldsForSubmit(resolvedFormProfile, dto)")) {
    fail(
      "[submit-required] Draft CREATE must not call assertProfileRequiredFieldsForSubmit (strict gates on OPEN/PUBLISH only)",
    );
  }
  if (!service.includes("assertTourStateReadyForOpenAfterPatch")) {
    fail("[submit-required] tours.service must enforce OPEN/PUBLISH via assertTourStateReadyForOpenAfterPatch");
  }
}

function extractRegisteredCapabilities() {
  const registrySrc = readRepo("packages/shared/rbac/capability-registry.ts");
  const capsSrc = readRepo("packages/shared/rbac/capabilities.ts");
  const registered = new Set();
  const start = registrySrc.indexOf("WORKSPACE_CAPABILITY_VALUES");
  if (start >= 0) {
    const slice = registrySrc.slice(start, start + 2500);
    const re = /"([a-zA-Z][a-zA-Z0-9_.]+)"/g;
    let match;
    while ((match = re.exec(slice)) !== null) {
      registered.add(match[1]);
    }
  }
  for (const name of [
    "TOUR_CAPABILITIES",
    "SETTINGS_CAPABILITIES",
    "MODULE_CAPABILITIES",
    "MARKETING_CAPABILITIES",
  ]) {
    const blockStart = capsSrc.indexOf(`export const ${name}`);
    if (blockStart < 0) {
      continue;
    }
    const block = capsSrc.slice(blockStart, blockStart + 1500);
    const re = /"([a-zA-Z][a-zA-Z0-9_.]+)"/g;
    let match;
    while ((match = re.exec(block)) !== null) {
      registered.add(match[1]);
    }
  }
  return registered;
}

function checkPatchPolicyCapabilityParity() {
  const policy = readRepo(TOUR_PATCH_CONTRACT_REL);
  const registered = extractRegisteredCapabilities();
  const used = new Set();
  const re = /requiredCapability:\s*"([^"]+)"/g;
  let match;
  while ((match = re.exec(policy)) !== null) {
    used.add(match[1]);
  }
  for (const cap of used) {
    if (!registered.has(cap)) {
      fail(`[patch-capability] tour-patch-field-policy uses unknown capability "${cap}"`);
    }
  }
  const coreCaps = new Set();
  const tripCaps = new Set();
  const groupRe = /group:\s*"(core|tripDetails)"[^{]*requiredCapability:\s*"([^"]+)"/g;
  while ((match = groupRe.exec(policy)) !== null) {
    if (match[1] === "core") {
      coreCaps.add(match[2]);
    } else {
      tripCaps.add(match[2]);
    }
  }
  if (!coreCaps.has("tour.update.core")) {
    fail("[patch-capability] policy core group must use tour.update.core");
  }
  if (!tripCaps.has("tour.update.tripDetails")) {
    fail("[patch-capability] policy tripDetails group must use tour.update.tripDetails");
  }
  if (coreCaps.size !== 1) {
    fail(`[patch-capability] expected single core capability, got: ${[...coreCaps].join(", ")}`);
  }
  if (tripCaps.size !== 1) {
    fail(
      `[patch-capability] expected single tripDetails capability, got: ${[...tripCaps].join(", ")}`,
    );
  }
}

function checkSubmitRequiredParityArtifacts() {
  const paritySpec = readRepo(
    "apps/web/src/features/tours/wizard/profileRules/submit-required-parity.spec.ts",
  );
  if (!paritySpec.includes("getRequiredSubmitFieldPathsForProfile")) {
    fail("[submit-required] web submit-required-parity.spec must use @repo/types paths");
  }
  if (!paritySpec.includes("requiredFieldsForProfile")) {
    fail("[submit-required] web submit-required-parity.spec must compare requiredFieldsForProfile");
  }

  const editParity = readRepo(
    "apps/web/src/features/tours/wizard/profileRules/edit-required-parity.spec.ts",
  );
  if (!editParity.includes("getEditRequiredTripDetailsPathsForProfile")) {
    fail("[edit-required] web edit-required-parity.spec must use @repo/types");
  }
}

function checkGovernanceEntrypoints() {
  for (const script of [
    "run-tour-governance.mjs",
    "audit-capability-registry.mjs",
  ]) {
    const abs = path.join(REPO_ROOT, "scripts", script);
    if (!fs.existsSync(abs)) {
      fail(`[governance] missing scripts/${script}`);
    }
  }
}

function checkMutationAbilityGroups() {
  const abilities = readRepo("apps/api/src/modules/tours/policies/assert-tour-mutation-abilities.ts");
  const policy = readRepo("apps/api/src/modules/tours/utils/tour-patch-field-policy.ts");

  const coreKeys = new Set();
  const tripKeys = new Set();
  const coreBlock = abilities.match(/CORE_PATCH_KEYS[\s\S]*?TRIP_DETAILS_PATCH_KEYS/);
  const tripBlock = abilities.match(/TRIP_DETAILS_PATCH_KEYS[\s\S]*?function forbidCapability/);
  if (coreBlock) {
    const re = /"([^"]+)"/g;
    let m;
    while ((m = re.exec(coreBlock[0])) !== null) {
      coreKeys.add(m[1]);
    }
  }
  if (tripBlock) {
    const re = /"([^"]+)"/g;
    let m;
    while ((m = re.exec(tripBlock[0])) !== null) {
      tripKeys.add(m[1]);
    }
  }

  const policyCore = new Set();
  const policyTrip = new Set();
  const ruleRe = /\{\s*dtoKey:\s*"([^"]+)"[\s\S]*?group:\s*"(core|tripDetails)"/g;
  let match;
  while ((match = ruleRe.exec(policy)) !== null) {
    if (match[2] === "core") {
      policyCore.add(match[1]);
    } else {
      policyTrip.add(match[1]);
    }
  }

  for (const key of policyCore) {
    if (!coreKeys.has(key)) {
      fail(
        `[casl-groups] policy core field ${key} missing from CORE_PATCH_KEYS in assert-tour-mutation-abilities`,
      );
    }
  }
  for (const key of policyTrip) {
    if (!tripKeys.has(key)) {
      fail(
        `[casl-groups] policy tripDetails field ${key} missing from TRIP_DETAILS_PATCH_KEYS`,
      );
    }
  }
}

checkPatchRankGateParity();
checkPatchDtoCoverage();
checkPatchPolicyCapabilityParity();
checkWritePipelineWiring();
checkSubmitRequiredWiring();
checkSubmitRequiredParityArtifacts();
checkGovernanceEntrypoints();
checkMutationAbilityGroups();

if (failures.length > 0) {
  for (const line of failures) {
  }
  process.exit(1);
}

/**
 * Automated debugger for the draft-engine GET endpoint.
 *
 * Performs OTP login (same dev flow as e2e helpers) and calls:
 *   GET /api/v2/workspaces/:tenantId/draft-engine/:draftKey
 *
 * Usage (from repo root):
 *   pnpm debug:draft-engine
 *   pnpm --dir apps/api exec node --import tsx ../../scripts/debug-draft-engine.ts
 *
 * Optional: node --env-file=apps/api/.env … when DB-backed env vars are needed.
 *   DRAFT_DEBUG_API_BASE       default http://127.0.0.1:3001
 *   DRAFT_DEBUG_TENANT_SUBDOMAIN default denali
 *   DRAFT_DEBUG_PHONE            default +989121000001
 *   DRAFT_DEBUG_OTP              default 1234
 *   DRAFT_DEBUG_DRAFT_KEY        default denali-create
 *   DRAFT_DEBUG_WORKSPACE_ID     optional; otherwise read from JWT tenant_id
 *   TENANT_ROOT_DOMAIN           default localhost
 */

import assert from "node:assert/strict";
import http from "node:http";
import https from "node:https";
import { URL } from "node:url";

const E2E_DEV_OTP = "1234";

function readEnv(name: string, fallback: string): string {
  const value = process.env[name]?.trim();
  return value && value.length > 0 ? value : fallback;
}

function tenantHost(slug: string): string {
  const tenantRoot = readEnv("TENANT_ROOT_DOMAIN", "localhost");
  if (tenantRoot === "localhost") {
    // Match e2e helpers (`tenantTestHost`) — port belongs on the URL, not the Host header.
    return `${slug}.localhost`;
  }
  return `${slug}.${tenantRoot}`;
}

type HttpJsonResult = {
  status: number;
  body: unknown;
  headers: Record<string, string>;
};

/**
 * Node fetch overwrites Host when the URL is an IP; use http.request so tenant Host
 * matches e2e `tenantTestHost` / supertest `.set("Host", ...)`.
 */
function httpJson(params: {
  method: "GET" | "POST" | "PATCH" | "DELETE";
  url: string;
  hostHeader: string;
  headers?: Record<string, string>;
  body?: unknown;
}): Promise<HttpJsonResult> {
  const target = new URL(params.url);
  const transport = target.protocol === "https:" ? https : http;
  const payload =
    params.body === undefined ? undefined : JSON.stringify(params.body);

  return new Promise((resolve, reject) => {
    const req = transport.request(
      {
        protocol: target.protocol,
        hostname: target.hostname,
        port: target.port || (target.protocol === "https:" ? 443 : 80),
        path: `${target.pathname}${target.search}`,
        method: params.method,
        headers: {
          Host: params.hostHeader,
          Accept: "application/json",
          ...(payload != null ? { "Content-Type": "application/json", "Content-Length": Buffer.byteLength(payload) } : {}),
          ...params.headers,
        },
      },
      (res) => {
        const chunks: Buffer[] = [];
        res.on("data", (chunk: Buffer) => chunks.push(chunk));
        res.on("end", () => {
          const text = Buffer.concat(chunks).toString("utf8");
          let body: unknown = text.length > 0 ? text : null;
          try {
            body = text.length > 0 ? (JSON.parse(text) as unknown) : null;
          } catch {
            /* keep raw text */
          }
          const headers: Record<string, string> = {};
          for (const [key, value] of Object.entries(res.headers)) {
            if (value != null) {
              headers[key] = Array.isArray(value) ? value.join(", ") : String(value);
            }
          }
          resolve({ status: res.statusCode ?? 0, body, headers });
        });
      },
    );
    req.on("error", reject);
    if (payload != null) {
      req.write(payload);
    }
    req.end();
  });
}

function decodeJwtPayload(token: string): Record<string, unknown> {
  const segment = token.split(".")[1];
  if (!segment) {
    throw new Error("Invalid JWT: missing payload segment");
  }
  const padded = segment.replace(/-/g, "+").replace(/_/g, "/");
  const json = Buffer.from(padded, "base64").toString("utf8");
  return JSON.parse(json) as Record<string, unknown>;
}

async function loginWithOtp(params: {
  apiBase: string;
  hostHeader: string;
  phone: string;
  otp: string;
}): Promise<{ token: string; body: unknown }> {
  const url = `${params.apiBase.replace(/\/$/, "")}/api/v2/auth/web/session/otp`;

  const res = await httpJson({
    method: "POST",
    url,
    hostHeader: params.hostHeader,
    body: { phone: params.phone, otp: params.otp },
  });

  if (res.status < 200 || res.status >= 300) {
    throw new Error(
      `OTP login failed: HTTP ${res.status} ${JSON.stringify(res.body)}`,
    );
  }

  const body = res.body;
  const sessionToken =
    typeof body === "object" &&
    body != null &&
    "session_token" in body &&
    typeof (body as { session_token?: unknown }).session_token === "string"
      ? (body as { session_token: string }).session_token
      : null;

  if (!sessionToken) {
    throw new Error(`OTP login response missing session_token: ${JSON.stringify(body)}`);
  }

  return { token: sessionToken, body };
}

async function patchDraftSnapshot(params: {
  apiBase: string;
  hostHeader: string;
  token: string;
  workspaceId: string;
  draftKey: string;
  body: {
    data: Record<string, unknown>;
    version: number;
    schemaVersion?: number;
    lastModified: number;
  };
}): Promise<{ status: number; body: unknown; headers: Record<string, string> }> {
  const path = `/api/v2/workspaces/${encodeURIComponent(params.workspaceId)}/draft-engine/${encodeURIComponent(params.draftKey)}`;
  const url = `${params.apiBase.replace(/\/$/, "")}${path}`;

  return httpJson({
    method: "PATCH",
    url,
    hostHeader: params.hostHeader,
    headers: {
      Authorization: `Bearer ${params.token}`,
    },
    body: params.body,
  });
}

async function _deleteDraftSnapshot(params: {
  apiBase: string;
  hostHeader: string;
  token: string;
  workspaceId: string;
  draftKey: string;
}): Promise<{ status: number; body: unknown }> {
  const path = `/api/v2/workspaces/${encodeURIComponent(params.workspaceId)}/draft-engine/${encodeURIComponent(params.draftKey)}`;
  const url = `${params.apiBase.replace(/\/$/, "")}${path}`;

  return httpJson({
    method: "DELETE",
    url,
    hostHeader: params.hostHeader,
    headers: {
      Authorization: `Bearer ${params.token}`,
    },
  });
}

async function fetchDraftSnapshot(params: {
  apiBase: string;
  hostHeader: string;
  token: string;
  workspaceId: string;
  draftKey: string;
}): Promise<{ status: number; body: unknown; headers: Record<string, string> }> {
  const path = `/api/v2/workspaces/${encodeURIComponent(params.workspaceId)}/draft-engine/${encodeURIComponent(params.draftKey)}`;
  const url = `${params.apiBase.replace(/\/$/, "")}${path}`;


  return httpJson({
    method: "GET",
    url,
    hostHeader: params.hostHeader,
    headers: {
      Authorization: `Bearer ${params.token}`,
    },
  });
}

async function main(): Promise<void> {
  const apiBase = readEnv("DRAFT_DEBUG_API_BASE", "http://127.0.0.1:3001");
  const tenantSubdomain = readEnv("DRAFT_DEBUG_TENANT_SUBDOMAIN", "denali");
  const phone = readEnv("DRAFT_DEBUG_PHONE", "+989121000001");
  const otp = readEnv("DRAFT_DEBUG_OTP", E2E_DEV_OTP);
  const draftKey =
    readEnv("DRAFT_DEBUG_DRAFT_KEY", "") ||
    `debug-occ-${Date.now().toString(36)}`;
  const hostHeader = tenantHost(tenantSubdomain);


  const { token } = await loginWithOtp({ apiBase, hostHeader, phone, otp });
  const jwt = decodeJwtPayload(token);

  const workspaceIdFromEnv = readEnv("DRAFT_DEBUG_WORKSPACE_ID", "");
  const workspaceId =
    workspaceIdFromEnv ||
    (typeof jwt.tenant_id === "string" && jwt.tenant_id.trim()) ||
    (typeof jwt.tenantId === "string" && jwt.tenantId.trim()) ||
    "";

  if (!workspaceId) {
    throw new Error(
      "Could not resolve workspace UUID from JWT (tenant_id). Set DRAFT_DEBUG_WORKSPACE_ID.",
    );
  }

  const userId =
    (typeof jwt.sub === "string" && jwt.sub) ||
    (typeof jwt.user_id === "string" && jwt.user_id) ||
    "unknown";


  const draftResponse = await fetchDraftSnapshot({
    apiBase,
    hostHeader,
    token,
    workspaceId,
    draftKey,
  });


  if (draftResponse.body == null) {
  }


  const patchPayload = {
    data: { probe: "draft-engine-debug", step: 0 },
    lastModified: Date.now(),
  };

  const createRes = await patchDraftSnapshot({
    apiBase,
    hostHeader,
    token,
    workspaceId,
    draftKey,
    body: { ...patchPayload, version: 0, schemaVersion: 1 },
  });
  assert.ok(
    createRes.status >= 200 && createRes.status < 300,
    `create PATCH should succeed (got ${createRes.status})`,
  );
  const baseVersion =
    typeof createRes.body === "object" &&
    createRes.body != null &&
    "version" in createRes.body &&
    typeof (createRes.body as { version?: unknown }).version === "number"
      ? (createRes.body as { version: number }).version
      : 1;

  const bumpRes = await patchDraftSnapshot({
    apiBase,
    hostHeader,
    token,
    workspaceId,
    draftKey,
    body: {
      data: { probe: "draft-engine-debug", step: 1 },
      version: baseVersion,
      schemaVersion: 1,
      lastModified: Date.now(),
    },
  });
  assert.ok(bumpRes.status >= 200 && bumpRes.status < 300, "bump PATCH should succeed");

  const bumpedVersion =
    typeof bumpRes.body === "object" &&
    bumpRes.body != null &&
    "version" in bumpRes.body &&
    typeof (bumpRes.body as { version?: unknown }).version === "number"
      ? (bumpRes.body as { version: number }).version
      : baseVersion + 1;

  assert.ok(
    bumpedVersion > baseVersion,
    `bump must advance version (got ${bumpedVersion}, was ${baseVersion})`,
  );

  const staleRes = await patchDraftSnapshot({
    apiBase,
    hostHeader,
    token,
    workspaceId,
    draftKey,
    body: {
      data: { probe: "draft-engine-debug", step: 2 },
      version: baseVersion,
      schemaVersion: 1,
      lastModified: Date.now(),
    },
  });
  assert.equal(staleRes.status, 409, "stale PATCH must return 409 Conflict");
  const staleServer =
    typeof staleRes.body === "object" &&
    staleRes.body != null &&
    "error" in staleRes.body &&
    typeof (staleRes.body as { error?: { details?: { server?: unknown } } }).error?.details?.server ===
      "object"
      ? (staleRes.body as { error: { details: { server: unknown } } }).error.details.server
      : null;
  assert.ok(staleServer != null, "409 response must include error.details.server for client recovery");

  const errorCode =
    typeof draftResponse.body === "object" &&
    draftResponse.body != null &&
    "error" in draftResponse.body &&
    typeof (draftResponse.body as { error?: { code?: unknown } }).error?.code === "string"
      ? (draftResponse.body as { error: { code: string } }).error.code
      : null;
  if (errorCode === "SCHEMA_DRIFT_MISSING_TABLE") {
  }



  if (draftResponse.status < 200 || draftResponse.status >= 300) {
    process.exitCode = 1;
  }
}

main().catch((error: unknown) => {
  process.exitCode = 1;
});

#!/usr/bin/env node
/**
 * Rewrites direct feature-internal imports to the nearest index.ts barrel.
 *
 * Targets ESLint no-restricted-imports violations (features/* internal imports).
 *
 * Usage:
 *   node scripts/fix-barrels.mjs           # dry-run
 *   node scripts/fix-barrels.mjs --write   # apply changes
 */
import { spawnSync } from "node:child_process";
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");
const WEB_ROOT = path.join(REPO_ROOT, "apps", "web");
const WEB_SRC = path.join(WEB_ROOT, "src");
const FEATURES_ROOT = path.join(WEB_SRC, "features");

const WRITE = process.argv.includes("--write");
const RESTRICTED_PATTERN = /\/features\/[^/]+\/.+/;

const IMPORT_FROM_RE = /from\s+["']([^"']+)["']\s*;?\s*$/;
const IMPORT_NAMED_RE =
  /^\s*import\s+(type\s+)?(?:(\*\s+as\s+(\w+))|(?:\{([^}]+)\}|(\w+)))\s+from\s+["']([^"']+)["'];?\s*$/;

function posix(p) {
  return p.split(path.sep).join("/");
}

function readText(filePath) {
  return fs.readFileSync(filePath, "utf8");
}

function writeText(filePath, content) {
  if (!WRITE) return;
  fs.mkdirSync(path.dirname(filePath), { recursive: true });
  fs.writeFileSync(filePath, content, "utf8");
}

function resolveModuleFile(specifier, importerPath) {
  const candidates = [];
  if (specifier.startsWith("@/")) {
    const sub = specifier.slice(2);
    const base = path.join(WEB_SRC, sub);
    candidates.push(base);
  } else if (specifier.startsWith(".")) {
    candidates.push(path.resolve(path.dirname(importerPath), specifier));
  } else if (specifier.includes("features/")) {
    const idx = specifier.indexOf("features/");
    candidates.push(path.join(WEB_SRC, specifier.slice(idx)));
    candidates.push(path.join(REPO_ROOT, specifier));
  }

  const exts = [".ts", ".tsx", ".mts", ".cts", ".js", ".mjs", ".unified"];
  for (const base of candidates) {
    if (fs.existsSync(base) && fs.statSync(base).isFile()) return base;
    for (const ext of exts) {
      const p = base + ext;
      if (fs.existsSync(p)) return p;
    }
    const indexTs = path.join(base, "index.ts");
    if (fs.existsSync(indexTs)) return indexTs;
  }
  return null;
}

function featureRootFor(targetAbsPath) {
  const rel = posix(path.relative(WEB_SRC, targetAbsPath));
  const m = rel.match(/^features\/([^/]+)\//);
  if (!m) return null;
  return path.join(FEATURES_ROOT, m[1]);
}

/**
 * ESLint no-restricted-imports forbids paths like features/NAME/child/...
 * The only valid public entry is features/NAME/index.ts (e.g. @/features/tours).
 */
function findNearestBarrel(targetAbsPath) {
  const featureRoot = featureRootFor(targetAbsPath);
  if (!featureRoot) return null;

  const indexPath = path.join(featureRoot, "index.ts");
  return { barrelDir: featureRoot, indexPath, created: !fs.existsSync(indexPath) };
}

function parseNamedImports(clause) {
  if (!clause) return [];
  return clause
    .split(",")
    .map((p) => p.trim())
    .filter(Boolean)
    .map((part) => {
      const m = part.match(/^type\s+(\w+)(?:\s+as\s+(\w+))?$/);
      if (m) return { name: m[2] ?? m[1], imported: m[1], isType: true };
      const m2 = part.match(/^(\w+)(?:\s+as\s+(\w+))?$/);
      if (m2) return { name: m2[2] ?? m2[1], imported: m2[1], isType: false };
      return null;
    })
    .filter(Boolean);
}

function extractExports(modulePath) {
  const text = readText(modulePath);
  const names = new Set();
  const typeNames = new Set();
  let hasDefault = false;

  for (const line of text.split("\n")) {
    const trimmed = line.trim();
    if (trimmed.startsWith("export default")) hasDefault = true;
    const exp = trimmed.match(
      /^export\s+(?:type\s+)?(?:async\s+)?(?:function|class|const|enum|interface|type)\s+(\w+)/,
    );
    if (exp) {
      if (/^export\s+type\s+/.test(trimmed)) typeNames.add(exp[1]);
      else names.add(exp[1]);
    }
    const block = trimmed.match(/^export\s+(?:type\s+)?\{([^}]+)\}/);
    if (block) {
      const isType = /^export\s+type\s+/.test(trimmed);
      for (const part of block[1].split(",")) {
        const p = part.trim();
        if (!p) continue;
        const m = p.match(/^(\w+)(?:\s+as\s+(\w+))?$/);
        if (!m) continue;
        if (isType) typeNames.add(m[2] ?? m[1]);
        else names.add(m[2] ?? m[1]);
      }
    }
  }
  return { names: [...names], typeNames: [...typeNames], hasDefault };
}

function relativeModuleRef(fromDir, targetModulePath) {
  const rel = path.relative(fromDir, targetModulePath);
  let ref = posix(rel);
  if (!ref.startsWith(".")) ref = `./${ref}`;
  ref = ref.replace(/\.(tsx?|mts|cts|unified)$/, "");
  if (ref.endsWith("/index")) ref = ref.slice(0, -"/index".length);
  return ref;
}

function formatImportPath(importerPath, barrelDir) {
  const relImporter = posix(path.relative(REPO_ROOT, importerPath));
  const useAlias =
    relImporter.startsWith("apps/web/src/") ||
    relImporter.startsWith("apps/web/app/") ||
    relImporter.startsWith("apps/web/tests/") ||
    relImporter.startsWith("apps/web/scripts/");

  if (useAlias) {
    const relBarrel = posix(path.relative(WEB_SRC, barrelDir));
    return `@/${relBarrel}`;
  }
  let rel = posix(path.relative(path.dirname(importerPath), barrelDir));
  if (!rel.startsWith(".")) rel = `./${rel}`;
  return rel;
}

function ensureBarrelExports(indexPath, targetModulePath, symbols) {
  let content = fs.existsSync(indexPath) ? readText(indexPath) : "";
  const relFromBarrel = relativeModuleRef(path.dirname(indexPath), targetModulePath);
  const valueNames = symbols.filter((s) => !s.isType).map((s) => s.imported);
  const typeOnly = symbols.filter((s) => s.isType).map((s) => s.imported);
  const defaultSym = symbols.find((s) => s.isDefault);

  const linesToAdd = [];
  if (defaultSym && !content.includes(`export { default`)) {
    linesToAdd.push(`export { default } from "${relFromBarrel}";`);
  }
  if (valueNames.length && !valueNames.every((n) => content.includes(`export { ${n}`) || content.includes(`, ${n}`))) {
    const missing = valueNames.filter(
      (n) => !new RegExp(`\\b${n}\\b`).test(content) || !content.includes(`from "${relFromBarrel}"`),
    );
    if (missing.length) linesToAdd.push(`export { ${missing.join(", ")} } from "${relFromBarrel}";`);
  }
  if (typeOnly.length) {
    const missing = typeOnly.filter((n) => !content.includes(`export type { ${n}`));
    if (missing.length) linesToAdd.push(`export type { ${missing.join(", ")} } from "${relFromBarrel}";`);
  }

  if (!linesToAdd.length) return content;

  const header = content.endsWith("\n") || content.length === 0 ? "" : "\n";
  return `${content}${header}${linesToAdd.join("\n")}\n`;
}

function collectViolations() {
  const outFile = path.join(REPO_ROOT, ".tmp-eslint-barrels.json");
  const result = spawnSync(
    "pnpm",
    ["eslint", ".", "-f", "json", "-o", outFile],
    { cwd: REPO_ROOT, encoding: "utf8", stdio: ["ignore", "pipe", "pipe"] },
  );
  if (!fs.existsSync(outFile)) {
    console.error("Failed to run eslint:", result.stderr || result.stdout);
    process.exit(1);
  }
  const reports = JSON.parse(readText(outFile));
  const violations = [];
  for (const file of reports) {
    for (const msg of file.messages) {
      if (msg.ruleId !== "no-restricted-imports") continue;
      const m = msg.message.match(/^'([^']+)' import is restricted/);
      if (!m) continue;
      violations.push({
        file: file.filePath,
        line: msg.line,
        specifier: m[1],
      });
    }
  }
  return violations;
}

function extractImportBlock(lines, violationLineIdx) {
  let start = violationLineIdx;
  while (start > 0 && !lines[start].trimStart().startsWith("import")) start -= 1;
  if (!lines[start].trimStart().startsWith("import")) return null;

  let end = start;
  while (end < lines.length && !lines[end].includes(";")) end += 1;
  const block = lines.slice(start, end + 1).join("\n");
  const fromM = block.match(IMPORT_FROM_RE);
  if (!fromM) return null;

  const spec = fromM[1];
  const isTypeOnly = /^import\s+type\s+/m.test(block);
  const nsM = block.match(/import\s+(?:type\s+)?\*\s+as\s+(\w+)/);
  const defM = block.match(/import\s+(?:type\s+)?(\w+)\s+from/);
  const namedM = block.match(/import\s+(?:type\s+)?\{([\s\S]+?)\}\s+from/);

  let symbols = [];
  if (nsM) {
    symbols = [{ name: nsM[1], imported: "*", isType: false, isNamespace: true }];
  } else if (defM && !namedM) {
    symbols = [{ name: defM[1], imported: "default", isType: false, isDefault: true }];
  } else if (namedM) {
    symbols = parseNamedImports(namedM[1].replace(/\s+/g, " ")).map((s) => ({
      ...s,
      isType: s.isType || isTypeOnly,
    }));
  }

  return { start, end, spec, symbols, block };
}

function applyFix(violation) {
  const { file: importerPath, line, specifier } = violation;
  if (!RESTRICTED_PATTERN.test(specifier.replace(/^@\//, "src/"))) return null;

  const lines = readText(importerPath).split("\n");
  const lineIdx = line - 1;

  let parsed = extractImportBlock(lines, lineIdx);
  if (!parsed) {
    const m = lines[lineIdx]?.match(IMPORT_NAMED_RE);
    if (!m) return null;
    const isTypeOnly = Boolean(m[1]);
    parsed = {
      start: lineIdx,
      end: lineIdx,
      spec: m[6],
      symbols: m[3]
        ? [{ name: m[3], imported: "*", isType: false, isNamespace: true }]
        : m[5]
          ? [{ name: m[5], imported: "default", isType: false, isDefault: true }]
          : parseNamedImports(m[4]).map((s) => ({ ...s, isType: s.isType || isTypeOnly })),
      block: lines[lineIdx],
    };
  }

  if (parsed.spec !== specifier) return null;

  const targetModule = resolveModuleFile(specifier, importerPath);
  if (!targetModule) {
    return { error: `Could not resolve module for ${specifier} (${importerPath}:${line})` };
  }

  const barrel = findNearestBarrel(targetModule);
  if (!barrel) return { error: `No feature root for ${targetModule}` };

  const newBarrelContent = ensureBarrelExports(barrel.indexPath, targetModule, parsed.symbols);
  const newSpec = formatImportPath(importerPath, barrel.barrelDir);
  const newBlock = parsed.block.replace(
    /from\s+["'][^"']+["']/,
    `from "${newSpec}"`,
  );

  return {
    importerPath,
    start: parsed.start,
    end: parsed.end,
    newBlock,
    barrel,
    newBarrelContent,
    oldSpec: specifier,
    newSpec,
  };
}

function main() {
  const violations = collectViolations();
  console.log(`Found ${violations.length} barrel-only (no-restricted-imports) violations`);
  if (!violations.length) return;

  const barrelEdits = new Map();
  const fileLineEdits = new Map();
  const errors = [];

  for (const v of violations) {
    const fix = applyFix(v);
    if (!fix) continue;
    if (fix.error) {
      errors.push(fix.error);
      continue;
    }
    if (!fileLineEdits.has(fix.importerPath)) fileLineEdits.set(fix.importerPath, []);
    fileLineEdits.get(fix.importerPath).push(fix);
    barrelEdits.set(fix.barrel.indexPath, fix.newBarrelContent);
    console.log(
      `${WRITE ? "fix" : "plan"}: ${posix(path.relative(REPO_ROOT, fix.importerPath))}:${fix.start + 1}`,
    );
    console.log(`  ${fix.oldSpec} → ${fix.newSpec}`);
  }

  if (errors.length) {
    console.error("\nErrors:");
    for (const e of errors) console.error(`  - ${e}`);
  }

  if (!WRITE) {
    console.log(`\nDry run: ${fileLineEdits.size} files, ${barrelEdits.size} barrels. Pass --write to apply.`);
    return;
  }

  for (const [indexPath, content] of barrelEdits) {
    writeText(indexPath, content);
  }
  for (const [importerPath, fixes] of fileLineEdits) {
    const lines = readText(importerPath).split("\n");
    const ordered = [...fixes].sort((a, b) => b.start - a.start);
    for (const fix of ordered) {
      const replacement = fix.newBlock.split("\n");
      lines.splice(fix.start, fix.end - fix.start + 1, ...replacement);
    }
    writeText(importerPath, lines.join("\n"));
  }

  const after = collectViolations();
  console.log(`\nApplied. Remaining barrel violations: ${after.length}`);
}

main();

#!/usr/bin/env node
/**
 * Builds an NDJSON sample from live API/BFF error responses (structured envelope).
 * Use when you do not yet have a production log drain export.
 *
 *   node scripts/generate-production-log-sample.mjs > /tmp/sample.ndjson
 *   PRODUCTION_LOG_SAMPLE=/tmp/sample.ndjson pnpm infra:signoff
 */
const API = process.env.API_PORT ?? "3001";
const WEB = process.env.WEB_PORT ?? "3000";

async function record(status, body, requestId) {
  const code =
    body?.error?.code ??
    body?.error_code ??
    body?.code ??
    (typeof body?.error === "string" ? body.error : undefined);
  return JSON.stringify({
    level: status >= 500 ? "error" : "warn",
    status,
    error_code: code,
    message: body?.error?.message ?? body?.message ?? "http_request_failed",
    request_id: requestId ?? body?.error?.requestId ?? body?.requestId,
  });
}

async function main() {
  const lines = [];

  const noAuth = await fetch(`http://127.0.0.1:${API}/api/v2/tours`, {
    headers: { Host: `ws1-rbac.localhost:${WEB}` },
  });
  const noAuthBody = await noAuth.json().catch(() => ({}));
  lines.push(await record(noAuth.status, noAuthBody));

  const badOtp = await fetch(`http://ws1-rbac.localhost:${WEB}/api/auth/login-web-session`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ phone: "+15550009999", otp: "0000" }),
  });
  const badBody = await badOtp.json().catch(() => ({}));
  lines.push(await record(badOtp.status, badBody));

  const ok = await fetch(`http://127.0.0.1:${API}/health`);
  lines.push(JSON.stringify({ level: "info", status: ok.status, message: "http_request_completed" }));

  process.stdout.write(`${lines.join("\n")}\n`);
}

main().catch((e) => {
  process.exit(1);
});

#!/usr/bin/env node
/**
 * Concurrent workspace-host probes across ws1/ws2/ws3 (Phase 7.5 — staging/local).
 */
import { performance } from "node:perf_hooks";
import { spawnSync } from "node:child_process";

const SLUGS = (process.env.LOAD_TENANT_SLUGS ?? "ws1-rbac,ws2-rbac,ws3-rbac")
  .split(",")
  .map((s) => s.trim())
  .filter(Boolean);
const ROOT = process.env.LOAD_TENANT_ROOT ?? "localhost";
const PORT = process.env.LOAD_API_PORT ?? "3001";
const CONCURRENCY = Number(process.env.LOAD_CONCURRENCY ?? "30");
const ROUNDS = Number(process.env.LOAD_ROUNDS ?? "3");
const PATH = process.env.LOAD_PROBE_PATH ?? "/api/v2/auth/workspace-host";

function probe(slug) {
  const host = `${slug}.${ROOT}:${PORT}`;
  const t0 = performance.now();
  const r = spawnSync(
    "curl",
    [
      "-sf",
      "-o",
      "/dev/null",
      "-w",
      "%{http_code}",
      `http://127.0.0.1:${PORT}${PATH}`,
      "-H",
      `Host: ${host}`,
    ],
    { encoding: "utf8" },
  );
  return {
    slug,
    ms: performance.now() - t0,
    ok: r.status === 0,
    status: (r.stdout || "").trim(),
  };
}

const health = spawnSync("curl", ["-sf", `http://127.0.0.1:${PORT}/health`], { encoding: "utf8" });
if (health.status !== 0) {
  process.exit(0);
}

const samples = [];
for (let round = 0; round < ROUNDS; round += 1) {
  for (let i = 0; i < CONCURRENCY; i += 1) {
    const slug = SLUGS[i % SLUGS.length];
    samples.push(probe(slug));
  }
}

const ms = samples.map((s) => s.ms).sort((a, b) => a - b);
const p95 = ms[Math.min(ms.length - 1, Math.floor(ms.length * 0.95))];
const p50 = ms[Math.floor(ms.length * 0.5)];
const errors = samples.filter((s) => !s.ok || (s.status !== "204" && s.status !== "200")).length;


if (errors > samples.length * 0.05) {
  process.exit(1);
}

#!/usr/bin/env node
/**
 * Infrastructure closure — automated debt scan (Phase 4).
 *
 * Fails CI when unallowlisted matches are found for:
 * - legacy tenant resolver patterns
 * - browser-direct Nest API calls (apiClient usage outside BFF)
 * - generic `throw new Error` in core auth/BFF/tenant paths
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(__dirname, "..");
const ALLOWLIST_PATH = path.join(__dirname, "infrastructure-debt.allowlist.json");

function normPosix(p) {
  return p.split(path.sep).join("/");
}

function readAllowlist() {
  return JSON.parse(fs.readFileSync(ALLOWLIST_PATH, "utf8"));
}

function walk(dir, acc = [], ext = ".ts") {
  if (!fs.existsSync(dir)) return acc;
  for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
    const p = path.join(dir, ent.name);
    if (ent.isDirectory()) {
      if (ent.name === "node_modules" || ent.name === "dist" || ent.name === ".next") continue;
      walk(p, acc, ext);
    } else if (ent.isFile() && (ext === ".ts" ? ent.name.endsWith(".ts") || ent.name.endsWith(".tsx") : ent.name.endsWith(ext))) {
      acc.push(p);
    }
  }
  return acc;
}

function lineAt(src, idx) {
  return src.slice(0, idx).split("\n").length;
}

/** Removed helpers — must not reappear. */
function checkLegacyTenantResolvers(allow) {
  const banned = [
    { re: /resolve-tenant-context-helpers/g, label: "resolve-tenant-context-helpers" },
    { re: /\bfallbackTenant(?:Slug|Id)?\s*=/g, label: "fallbackTenant assignment" },
    { re: /\bdefaultTenant(?:Slug|Id)?\s*=/g, label: "defaultTenant assignment" },
    { re: /['"]default['"]\s*as\s+tenant/gi, label: "default-as-tenant literal" },
  ];
  const roots = [
    path.join(REPO_ROOT, "apps/web/lib/tenant"),
    path.join(REPO_ROOT, "apps/web/middleware.ts"),
    path.join(REPO_ROOT, "apps/api/src/common/tenant"),
  ];
  const allowed = new Set((allow.legacyTenantResolverPaths ?? []).map(normPosix));
  const violations = [];

  for (const root of roots) {
    const files = fs.existsSync(root) && fs.statSync(root).isFile()
      ? [root]
      : walk(root).concat(root.endsWith(".ts") ? [] : []);
    const unique = [...new Set(files)];
    for (const abs of unique) {
      const rel = normPosix(path.relative(REPO_ROOT, abs));
      if (allowed.has(rel)) continue;
      const text = fs.readFileSync(abs, "utf8");
      for (const { re, label } of banned) {
        re.lastIndex = 0;
        let m;
        while ((m = re.exec(text)) !== null) {
          violations.push(
            `[LEGACY_TENANT_RESOLVER] ${rel}:${lineAt(text, m.index)} — ${label}`,
          );
        }
      }
    }
  }
  return violations;
}

/** Direct cross-origin API from browser (hybrid bypass). */
function checkDirectApiCalls(allow) {
  const webRoot = path.join(REPO_ROOT, "apps/web");
  const allowed = new Set((allow.directApiClientPaths ?? []).map(normPosix));
  const violations = [];
  const re = /\bapiClient\.(get|post|patch|put|delete)\s*\(/g;

  for (const abs of walk(webRoot)) {
    const rel = normPosix(path.relative(REPO_ROOT, abs));
    if (rel.includes("/tests/") || rel.endsWith(".spec.ts") || rel.endsWith(".spec.tsx")) continue;
    if (allowed.has(rel)) continue;
    const text = fs.readFileSync(abs, "utf8");
    if (!re.test(text)) continue;
    re.lastIndex = 0;
    let m;
    while ((m = re.exec(text)) !== null) {
      violations.push(
        `[DIRECT_API_CALL] ${rel}:${lineAt(text, m.index)} — apiClient.${m[1]}() must use BFF (/api/*) or add to infrastructure-debt.allowlist.json with migration ticket`,
      );
    }
  }
  return violations;
}

/** Untyped failures in core infrastructure paths. */
function checkGenericErrorThrows(allow) {
  const scanRoots = [
    "apps/web/lib/api",
    "apps/web/lib/tenant",
    "apps/api/src/common/auth",
    "apps/api/src/common/middleware",
  ];
  const allowed = new Set((allow.genericErrorThrowPaths ?? []).map(normPosix));
  const violations = [];
  const re = /throw\s+new\s+Error\s*\(/g;

  for (const relRoot of scanRoots) {
    const absRoot = path.join(REPO_ROOT, relRoot);
    if (!fs.existsSync(absRoot)) continue;
    const files = fs.statSync(absRoot).isFile() ? [absRoot] : walk(absRoot);
    for (const abs of files) {
      const rel = normPosix(path.relative(REPO_ROOT, abs));
      if (rel.endsWith(".spec.ts")) continue;
      if (allowed.has(rel)) continue;
      const text = fs.readFileSync(abs, "utf8");
      if (!re.test(text)) continue;
      re.lastIndex = 0;
      let m;
      while ((m = re.exec(text)) !== null) {
        violations.push(
          `[GENERIC_ERROR_THROW] ${rel}:${lineAt(text, m.index)} — use AppError / GlobalErrorTaxonomy in core flows`,
        );
      }
    }
  }
  return violations;
}

function main() {
  const allow = readAllowlist();
  const violations = [
    ...checkLegacyTenantResolvers(allow),
    ...checkDirectApiCalls(allow),
    ...checkGenericErrorThrows(allow),
  ];

  if (violations.length === 0) {
    process.exit(0);
  }

  for (const v of violations) {
  }
